//+------------------------------------------------------------------+
//|                                US30_Range_Breakout_Backtest.mq4 |
//|                                    Estrategia de Rango US30      |
//|                                                                  |
//+------------------------------------------------------------------+
#property copyright "Trading Strategy Automation"
#property link      ""
#property version   "1.00"
#property strict

//--- Input parameters
input double RiskPercent = 1.0;           // Riesgo por operación (%)
input int    MaxPipsMove = 200;           // Máximo movimiento en pips para validar entrada
input int    MagicNumber = 123456;        // Número mágico
input bool   UseNewsFilter = true;        // Filtro de noticias
input string NewsTime = "10:00";          // Hora de noticias (formato HH:MM)

//--- Global variables
datetime lastTradeDate = 0;
double   rangeHigh = 0;
double   rangeHigh_Low = 0;
double   rangeLow = 0;
double   rangeLow_High = 0;
bool     rangeSet = false;
bool     tradingWindowActive = false;
int      consecutiveBullish = 0;
int      consecutiveBearish = 0;
bool     breakoutOccurred = false;
double   breakoutCandleLow = 0;
double   breakoutCandleHigh = 0;
datetime lastCandleTime = 0;
bool     tradeExecutedToday = false;
bool     newsEventToday = false;
datetime newsEventTime = 0;

//+------------------------------------------------------------------+
//| Expert initialization function                                   |
//+------------------------------------------------------------------+
int OnInit()
{
   Print("US30 Range Breakout Strategy - Backtesting Version Initialized");
   Print("Risk per trade: ", RiskPercent, "%");
   Print("Max pips movement: ", MaxPipsMove);
   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Expert deinitialization function                                 |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   Comment("");
}

//+------------------------------------------------------------------+
//| Expert tick function                                             |
//+------------------------------------------------------------------+
void OnTick()
{
   // Verificar si es un nuevo día
   if(TimeDayOfYear(TimeCurrent()) != TimeDayOfYear(lastTradeDate))
   {
      ResetDaily();
   }

   // Obtener hora actual
   datetime currentTime = TimeCurrent();
   int currentHour = TimeHour(currentTime);
   int currentMinute = TimeMinute(currentTime);

   // Paso #1: Establecer rango entre 4:00 AM - 9:00 AM (NY time)
   if(currentHour >= 4 && currentHour < 9)
   {
      UpdateRange();
   }

   // Finalizar establecimiento del rango a las 9:00 AM
   if(currentHour == 9 && currentMinute == 0 && !rangeSet)
   {
      FinalizeRange();
   }

   // Paso #2: Ventana de trading 9:30 AM - 12:15 PM
   if((currentHour == 9 && currentMinute >= 30) || 
      (currentHour > 9 && currentHour < 12) ||
      (currentHour == 12 && currentMinute <= 15))
   {
      tradingWindowActive = true;

      // Verificar si hay noticias y ajustar tiempo
      if(UseNewsFilter && newsEventToday && currentTime < newsEventTime)
      {
         return; // Esperar hasta después de las noticias
      }
   }
   else
   {
      tradingWindowActive = false;
   }

   // Verificar nueva vela en timeframe de 1 minuto
   if(Period() != PERIOD_M1)
   {
      Print("WARNING: Este EA debe ejecutarse en gráfico M1");
   }

   datetime currentCandleTime = iTime(Symbol(), PERIOD_M1, 0);
   if(currentCandleTime != lastCandleTime)
   {
      lastCandleTime = currentCandleTime;

      // Paso #3: Ejecutar lógica de trading
      if(tradingWindowActive && rangeSet && !tradeExecutedToday)
      {
         CheckForEntry();
      }
   }

   // Paso #4: Gestión de trades abiertos (mover SL a BE al 80% del TP)
   ManageOpenTrades();

   // Actualizar información en pantalla
   UpdateDisplay();
}

//+------------------------------------------------------------------+
//| Reset daily variables                                            |
//+------------------------------------------------------------------+
void ResetDaily()
{
   lastTradeDate = TimeCurrent();
   rangeHigh = 0;
   rangeLow = 999999;
   rangeSet = false;
   tradingWindowActive = false;
   consecutiveBullish = 0;
   consecutiveBearish = 0;
   breakoutOccurred = false;
   tradeExecutedToday = false;

   // Verificar si hay noticias hoy
   CheckNewsToday();

   Print("Daily reset completed for: ", TimeToString(lastTradeDate, TIME_DATE));
}

//+------------------------------------------------------------------+
//| Update range during 4:00 AM - 9:00 AM                           |
//+------------------------------------------------------------------+
void UpdateRange()
{
   double high = iHigh(Symbol(), PERIOD_M1, 1);
   double low = iLow(Symbol(), PERIOD_M1, 1);

   if(high > rangeHigh) rangeHigh = high;
   if(low < rangeLow) rangeLow = low;
}

//+------------------------------------------------------------------+
//| Finalize range at 9:00 AM                                       |
//+------------------------------------------------------------------+
void FinalizeRange()
{
   if(rangeHigh > 0 && rangeLow < 999999)
   {
      rangeSet = true;
      Print("Range established: High = ", rangeHigh, " Low = ", rangeLow);

      // Dibujar rectángulo en el gráfico
      DrawRangeRectangle();
   }
}

//+------------------------------------------------------------------+
//| Draw range rectangle on chart                                    |
//+------------------------------------------------------------------+
void DrawRangeRectangle()
{
   string rectName = "RangeRect_" + TimeToString(TimeCurrent(), TIME_DATE);

   datetime startTime = StrToTime(TimeToString(TimeCurrent(), TIME_DATE) + " 09:30");
   datetime endTime = StrToTime(TimeToString(TimeCurrent(), TIME_DATE) + " 12:15");

   ObjectDelete(0, rectName);
   ObjectCreate(0, rectName, OBJ_RECTANGLE, 0, startTime, rangeHigh, endTime, rangeLow);
   ObjectSetInteger(0, rectName, OBJPROP_COLOR, clrGray);
   ObjectSetInteger(0, rectName, OBJPROP_STYLE, STYLE_SOLID);
   ObjectSetInteger(0, rectName, OBJPROP_WIDTH, 1);
   ObjectSetInteger(0, rectName, OBJPROP_BACK, true);
   ObjectSetInteger(0, rectName, OBJPROP_FILL, true);
}

//+------------------------------------------------------------------+
//| Check for entry conditions                                       |
//+------------------------------------------------------------------+
void CheckForEntry()
{
   double open1 = iOpen(Symbol(), PERIOD_M1, 1);
   double close1 = iClose(Symbol(), PERIOD_M1, 1);
   double high1 = iHigh(Symbol(), PERIOD_M1, 1);
   double low1 = iLow(Symbol(), PERIOD_M1, 1);

   double open2 = iOpen(Symbol(), PERIOD_M1, 2);
   double close2 = iClose(Symbol(), PERIOD_M1, 2);

   double open3 = iOpen(Symbol(), PERIOD_M1, 3);
   double close3 = iClose(Symbol(), PERIOD_M1, 3);

   bool isBullish1 = close1 > open1;
   bool isBullish2 = close2 > open2;
   bool isBullish3 = close3 > open3;

   bool isBearish1 = close1 < open1;
   bool isBearish2 = close2 < open2;
   bool isBearish3 = close3 < open3;

   // CASO COMPRAS: Ruptura alcista del máximo del rango
   if(!breakoutOccurred && high3 >= rangeHigh)
   {
      if(isBullish3 && isBullish2 && isBullish1)
      {
         // Verificar que el movimiento no exceda 200 pips
         double totalMove = (high1 - low3) / Point;
         if(Symbol() == "US30" || Symbol() == "US30.c" || StringFind(Symbol(), "US30") >= 0)
         {
            totalMove = totalMove / 10; // Ajuste para US30
         }

         if(totalMove <= MaxPipsMove)
         {
            double sl = low3;
            double slDistance = (close1 - sl) / Point;
            if(Symbol() == "US30" || Symbol() == "US30.c" || StringFind(Symbol(), "US30") >= 0)
            {
               slDistance = slDistance / 10;
            }
            double tp = close1 + (close1 - sl);

            ExecuteBuyOrder(sl, tp);
         }
         else
         {
            Print("Entrada ANULADA: Movimiento excede ", MaxPipsMove, " pips (", totalMove, " pips)");
         }
      }
   }

   // CASO VENTAS: Ruptura bajista del mínimo del rango
   if(!breakoutOccurred && low3 <= rangeLow)
   {
      if(isBearish3 && isBearish2 && isBearish1)
      {
         // Verificar que el movimiento no exceda 200 pips
         double totalMove = (high3 - low1) / Point;
         if(Symbol() == "US30" || Symbol() == "US30.c" || StringFind(Symbol(), "US30") >= 0)
         {
            totalMove = totalMove / 10;
         }

         if(totalMove <= MaxPipsMove)
         {
            double sl = high3;
            double slDistance = (sl - close1) / Point;
            if(Symbol() == "US30" || Symbol() == "US30.c" || StringFind(Symbol(), "US30") >= 0)
            {
               slDistance = slDistance / 10;
            }
            double tp = close1 - (sl - close1);

            ExecuteSellOrder(sl, tp);
         }
         else
         {
            Print("Entrada ANULADA: Movimiento excede ", MaxPipsMove, " pips (", totalMove, " pips)");
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Execute Buy Order                                                |
//+------------------------------------------------------------------+
void ExecuteBuyOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl);

   int ticket = OrderSend(Symbol(), OP_BUY, lotSize, Ask, 3, sl, tp, 
                         "US30 Range Breakout", MagicNumber, 0, clrGreen);

   if(ticket > 0)
   {
      Print("BUY Order opened: Ticket = ", ticket, " Lots = ", lotSize, " SL = ", sl, " TP = ", tp);
      tradeExecutedToday = true;
      breakoutOccurred = true;
   }
   else
   {
      Print("Error opening BUY order: ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//| Execute Sell Order                                               |
//+------------------------------------------------------------------+
void ExecuteSellOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl);

   int ticket = OrderSend(Symbol(), OP_SELL, lotSize, Bid, 3, sl, tp, 
                         "US30 Range Breakout", MagicNumber, 0, clrRed);

   if(ticket > 0)
   {
      Print("SELL Order opened: Ticket = ", ticket, " Lots = ", lotSize, " SL = ", sl, " TP = ", tp);
      tradeExecutedToday = true;
      breakoutOccurred = true;
   }
   else
   {
      Print("Error opening SELL order: ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//| Calculate Lot Size based on risk percentage                      |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice)
{
   double riskAmount = AccountBalance() * RiskPercent / 100.0;
   double slDistance;

   if(OrderType() == OP_BUY || Ask > 0)
      slDistance = MathAbs(Ask - slPrice);
   else
      slDistance = MathAbs(Bid - slPrice);

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);

   double lotSize = (riskAmount / (slDistance / tickSize * tickValue));

   // Normalizar lote
   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   return lotSize;
}

//+------------------------------------------------------------------+
//| Manage open trades (move SL to BE at 80% TP)                    |
//+------------------------------------------------------------------+
void ManageOpenTrades()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(OrderSelect(i, SELECT_BY_POS, MODE_TRADES))
      {
         if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
         {
            double openPrice = OrderOpenPrice();
            double sl = OrderStopLoss();
            double tp = OrderTakeProfit();

            if(OrderType() == OP_BUY)
            {
               double distance = tp - openPrice;
               double eightyPercent = openPrice + (distance * 0.8);

               if(Bid >= eightyPercent && sl < openPrice)
               {
                  bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);
                  if(result)
                     Print("SL moved to BE for BUY order #", OrderTicket());
               }
            }
            else if(OrderType() == OP_SELL)
            {
               double distance = openPrice - tp;
               double eightyPercent = openPrice - (distance * 0.8);

               if(Ask <= eightyPercent && sl > openPrice)
               {
                  bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);
                  if(result)
                     Print("SL moved to BE for SELL order #", OrderTicket());
               }
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Check if there are news events today                            |
//+------------------------------------------------------------------+
void CheckNewsToday()
{
   if(!UseNewsFilter) return;

   // Esta función debe ser personalizada con un calendario económico
   // Por ahora, usa la hora configurada manualmente
   string todayDate = TimeToString(TimeCurrent(), TIME_DATE);
   newsEventTime = StrToTime(todayDate + " " + NewsTime);
   newsEventToday = true;

   Print("News event scheduled for: ", TimeToString(newsEventTime));
}

//+------------------------------------------------------------------+
//| Update display information                                       |
//+------------------------------------------------------------------+
void UpdateDisplay()
{
   string info = "\n=== US30 RANGE BREAKOUT STRATEGY ===\n";
   info += "Range High: " + DoubleToString(rangeHigh, Digits) + "\n";
   info += "Range Low: " + DoubleToString(rangeLow, Digits) + "\n";
   info += "Range Set: " + (rangeSet ? "YES" : "NO") + "\n";
   info += "Trading Window: " + (tradingWindowActive ? "ACTIVE" : "INACTIVE") + "\n";
   info += "Trade Executed Today: " + (tradeExecutedToday ? "YES" : "NO") + "\n";
   info += "Account Balance: $" + DoubleToString(AccountBalance(), 2) + "\n";

   Comment(info);
}
//+------------------------------------------------------------------+

