//+------------------------------------------------------------------+
//|                                  US30_Range_Breakout_Live.mq4   |
//|                                    Estrategia de Rango US30      |
//|                                          TRADING EN VIVO         |
//+------------------------------------------------------------------+
#property copyright "Trading Strategy Automation"
#property link      ""
#property version   "1.00"
#property strict

//--- Input parameters
input double RiskPercent = 1.0;           // Riesgo por operación (%)
input int    MaxPipsMove = 200;           // Máximo movimiento en pips para validar entrada
input int    MagicNumber = 123456;        // Número mágico único
input bool   EnableAlerts = true;         // Habilitar alertas
input bool   UseNewsFilter = true;        // Filtro de noticias
input string NewsTime = "10:00";          // Hora de noticias (formato HH:MM)
input int    Slippage = 3;                // Slippage permitido
input string Comment_Trades = "US30_RangeBO"; // Comentario en las operaciones

//--- Global variables
datetime lastTradeDate = 0;
double   rangeHigh = 0;
double   rangeLow = 0;
bool     rangeSet = false;
bool     tradingWindowActive = false;
datetime lastCandleTime = 0;
bool     tradeExecutedToday = false;
bool     newsEventToday = false;
datetime newsEventTime = 0;
bool     slMovedToBE = false;

// Variables para líneas en el gráfico
string lineHighName = "RangeHigh";
string lineLowName = "RangeLow";
string rectName = "TradingWindow";

//+------------------------------------------------------------------+
//| Expert initialization function                                   |
//+------------------------------------------------------------------+
int OnInit()
{
   Print("==================================================");
   Print("US30 Range Breakout Strategy - LIVE TRADING");
   Print("==================================================");
   Print("Risk per trade: ", RiskPercent, "%");
   Print("Max pips movement: ", MaxPipsMove);
   Print("Magic Number: ", MagicNumber);
   Print("==================================================");

   // Verificar que estamos en M1
   if(Period() != PERIOD_M1)
   {
      Alert("ADVERTENCIA: Este EA debe ejecutarse en gráfico M1");
      Print("ERROR: Gráfico debe ser M1. Actual: ", Period());
   }

   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Expert deinitialization function                                 |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   // Limpiar objetos del gráfico
   ObjectDelete(0, lineHighName);
   ObjectDelete(0, lineLowName);
   ObjectDelete(0, rectName);
   Comment("");

   Print("EA detenido. Razón: ", reason);
}

//+------------------------------------------------------------------+
//| Expert tick function                                             |
//+------------------------------------------------------------------+
void OnTick()
{
   // Verificar si es un nuevo día
   if(TimeDayOfYear(TimeCurrent()) != TimeDayOfYear(lastTradeDate))
   {
      ResetDaily();
   }

   // Obtener hora actual (hora del servidor)
   datetime currentTime = TimeCurrent();
   int currentHour = TimeHour(currentTime);
   int currentMinute = TimeMinute(currentTime);

   // PASO #1: Establecer rango entre 4:00 AM - 9:00 AM
   if(currentHour >= 4 && currentHour < 9)
   {
      UpdateRange();
   }

   // Finalizar establecimiento del rango a las 9:00 AM
   if(currentHour == 9 && currentMinute == 0 && !rangeSet)
   {
      FinalizeRange();
   }

   // PASO #2: Ventana de trading 9:30 AM - 12:15 PM
   tradingWindowActive = false;
   if((currentHour == 9 && currentMinute >= 30) || 
      (currentHour > 9 && currentHour < 12) ||
      (currentHour == 12 && currentMinute <= 15))
   {
      tradingWindowActive = true;

      // Verificar filtro de noticias
      if(UseNewsFilter && newsEventToday && currentTime < newsEventTime)
      {
         tradingWindowActive = false;
         Comment("Esperando finalización de noticias...\nNoticias programadas: ", 
                 TimeToString(newsEventTime, TIME_MINUTES));
         return;
      }
   }

   // Verificar nueva vela en M1
   datetime currentCandleTime = iTime(Symbol(), PERIOD_M1, 0);
   if(currentCandleTime != lastCandleTime)
   {
      lastCandleTime = currentCandleTime;

      // PASO #3: Ejecutar lógica de trading
      if(tradingWindowActive && rangeSet && !tradeExecutedToday)
      {
         CheckForEntry();
      }
   }

   // PASO #4: Gestión de trades abiertos
   ManageOpenTrades();

   // Actualizar información en pantalla
   UpdateDisplay();
}

//+------------------------------------------------------------------+
//| Reset daily variables                                            |
//+------------------------------------------------------------------+
void ResetDaily()
{
   Print("===== NUEVO DÍA DE TRADING =====");
   Print("Fecha: ", TimeToString(TimeCurrent(), TIME_DATE));

   lastTradeDate = TimeCurrent();
   rangeHigh = 0;
   rangeLow = 999999;
   rangeSet = false;
   tradingWindowActive = false;
   tradeExecutedToday = false;
   slMovedToBE = false;

   // Limpiar objetos del día anterior
   ObjectDelete(0, lineHighName);
   ObjectDelete(0, lineLowName);
   ObjectDelete(0, rectName);

   // Verificar si hay noticias hoy
   CheckNewsToday();

   Print("Variables reiniciadas correctamente");
}

//+------------------------------------------------------------------+
//| Update range during 4:00 AM - 9:00 AM                           |
//+------------------------------------------------------------------+
void UpdateRange()
{
   for(int i = 1; i < 300; i++) // Revisar últimas 5 horas (300 velas M1)
   {
      datetime barTime = iTime(Symbol(), PERIOD_M1, i);
      int barHour = TimeHour(barTime);

      if(barHour >= 4 && barHour < 9)
      {
         double high = iHigh(Symbol(), PERIOD_M1, i);
         double low = iLow(Symbol(), PERIOD_M1, i);

         if(high > rangeHigh) rangeHigh = high;
         if(low < rangeLow) rangeLow = low;
      }
   }
}

//+------------------------------------------------------------------+
//| Finalize range at 9:00 AM                                       |
//+------------------------------------------------------------------+
void FinalizeRange()
{
   if(rangeHigh > 0 && rangeLow < 999999)
   {
      rangeSet = true;
      Print("===== RANGO ESTABLECIDO =====");
      Print("Range High: ", rangeHigh);
      Print("Range Low: ", rangeLow);
      Print("Range Size: ", (rangeHigh - rangeLow) / Point, " points");

      // Dibujar líneas horizontales
      DrawRangeLines();

      if(EnableAlerts)
      {
         Alert("Rango establecido - High: ", rangeHigh, " Low: ", rangeLow);
      }
   }
   else
   {
      Print("ERROR: No se pudo establecer el rango correctamente");
   }
}

//+------------------------------------------------------------------+
//| Draw range lines on chart                                        |
//+------------------------------------------------------------------+
void DrawRangeLines()
{
   // Línea superior (máximo)
   ObjectDelete(0, lineHighName);
   ObjectCreate(0, lineHighName, OBJ_HLINE, 0, 0, rangeHigh);
   ObjectSetInteger(0, lineHighName, OBJPROP_COLOR, clrDodgerBlue);
   ObjectSetInteger(0, lineHighName, OBJPROP_STYLE, STYLE_SOLID);
   ObjectSetInteger(0, lineHighName, OBJPROP_WIDTH, 2);
   ObjectSetString(0, lineHighName, OBJPROP_TEXT, "Range High");

   // Línea inferior (mínimo)
   ObjectDelete(0, lineLowName);
   ObjectCreate(0, lineLowName, OBJ_HLINE, 0, 0, rangeLow);
   ObjectSetInteger(0, lineLowName, OBJPROP_COLOR, clrOrangeRed);
   ObjectSetInteger(0, lineLowName, OBJPROP_STYLE, STYLE_SOLID);
   ObjectSetInteger(0, lineLowName, OBJPROP_WIDTH, 2);
   ObjectSetString(0, lineLowName, OBJPROP_TEXT, "Range Low");

   // Rectángulo de ventana de trading
   datetime startTime = StrToTime(TimeToString(TimeCurrent(), TIME_DATE) + " 09:30");
   datetime endTime = StrToTime(TimeToString(TimeCurrent(), TIME_DATE) + " 12:15");

   ObjectDelete(0, rectName);
   ObjectCreate(0, rectName, OBJ_RECTANGLE, 0, startTime, rangeHigh, endTime, rangeLow);
   ObjectSetInteger(0, rectName, OBJPROP_COLOR, clrGray);
   ObjectSetInteger(0, rectName, OBJPROP_STYLE, STYLE_SOLID);
   ObjectSetInteger(0, rectName, OBJPROP_WIDTH, 1);
   ObjectSetInteger(0, rectName, OBJPROP_BACK, true);
   ObjectSetInteger(0, rectName, OBJPROP_FILL, false);
}

//+------------------------------------------------------------------+
//| Check for entry conditions (3 velas consecutivas)               |
//+------------------------------------------------------------------+
void CheckForEntry()
{
   // Obtener datos de las últimas 3 velas cerradas
   double open1 = iOpen(Symbol(), PERIOD_M1, 1);
   double close1 = iClose(Symbol(), PERIOD_M1, 1);
   double high1 = iHigh(Symbol(), PERIOD_M1, 1);
   double low1 = iLow(Symbol(), PERIOD_M1, 1);

   double open2 = iOpen(Symbol(), PERIOD_M1, 2);
   double close2 = iClose(Symbol(), PERIOD_M1, 2);
   double high2 = iHigh(Symbol(), PERIOD_M1, 2);
   double low2 = iLow(Symbol(), PERIOD_M1, 2);

   double open3 = iOpen(Symbol(), PERIOD_M1, 3);
   double close3 = iClose(Symbol(), PERIOD_M1, 3);
   double high3 = iHigh(Symbol(), PERIOD_M1, 3);
   double low3 = iLow(Symbol(), PERIOD_M1, 3);

   bool isBullish1 = close1 > open1;
   bool isBullish2 = close2 > open2;
   bool isBullish3 = close3 > open3;

   bool isBearish1 = close1 < open1;
   bool isBearish2 = close2 < open2;
   bool isBearish3 = close3 < open3;

   // CASO COMPRAS: Ruptura alcista
   if(high3 >= rangeHigh && isBullish3 && isBullish2 && isBullish1)
   {
      // Calcular movimiento total de las 3 velas
      double totalMove = CalculatePips(high1 - low3);

      Print("Señal de COMPRA detectada. Movimiento: ", totalMove, " pips");

      if(totalMove <= MaxPipsMove)
      {
         double entryPrice = Ask;
         double sl = low3;
         double slPips = CalculatePips(entryPrice - sl);
         double tp = entryPrice + (entryPrice - sl); // TP = mismo tamaño que SL

         Print("Preparando orden de COMPRA:");
         Print("Entry: ", entryPrice, " | SL: ", sl, " (", slPips, " pips) | TP: ", tp);

         ExecuteBuyOrder(sl, tp);
      }
      else
      {
         Print("ENTRADA ANULADA - Movimiento excede límite: ", totalMove, " pips > ", MaxPipsMove, " pips");
         if(EnableAlerts)
         {
            Alert("Entrada COMPRA anulada - Movimiento excesivo: ", totalMove, " pips");
         }
      }
   }

   // CASO VENTAS: Ruptura bajista
   if(low3 <= rangeLow && isBearish3 && isBearish2 && isBearish1)
   {
      // Calcular movimiento total de las 3 velas
      double totalMove = CalculatePips(high3 - low1);

      Print("Señal de VENTA detectada. Movimiento: ", totalMove, " pips");

      if(totalMove <= MaxPipsMove)
      {
         double entryPrice = Bid;
         double sl = high3;
         double slPips = CalculatePips(sl - entryPrice);
         double tp = entryPrice - (sl - entryPrice); // TP = mismo tamaño que SL

         Print("Preparando orden de VENTA:");
         Print("Entry: ", entryPrice, " | SL: ", sl, " (", slPips, " pips) | TP: ", tp);

         ExecuteSellOrder(sl, tp);
      }
      else
      {
         Print("ENTRADA ANULADA - Movimiento excede límite: ", totalMove, " pips > ", MaxPipsMove, " pips");
         if(EnableAlerts)
         {
            Alert("Entrada VENTA anulada - Movimiento excesivo: ", totalMove, " pips");
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate pips (ajuste para US30)                               |
//+------------------------------------------------------------------+
double CalculatePips(double priceDistance)
{
   double pips = priceDistance / Point;

   // Ajuste para US30 (indices generalmente usan divisor de 10)
   if(StringFind(Symbol(), "US30") >= 0 || StringFind(Symbol(), "DOW") >= 0)
   {
      pips = pips / 10.0;
   }

   return pips;
}

//+------------------------------------------------------------------+
//| Execute Buy Order                                                |
//+------------------------------------------------------------------+
void ExecuteBuyOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl, OP_BUY);

   if(lotSize > 0)
   {
      int ticket = OrderSend(Symbol(), OP_BUY, lotSize, Ask, Slippage, sl, tp, 
                            Comment_Trades, MagicNumber, 0, clrGreen);

      if(ticket > 0)
      {
         tradeExecutedToday = true;
         slMovedToBE = false;

         Print("===== ORDEN DE COMPRA EJECUTADA =====");
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
         Print("Precio entrada: ", Ask);
         Print("Stop Loss: ", sl);
         Print("Take Profit: ", tp);
         Print("Riesgo: ", RiskPercent, "% ($", AccountBalance() * RiskPercent / 100, ")");

         if(EnableAlerts)
         {
            Alert("COMPRA ejecutada - Ticket: ", ticket, " | Lotes: ", lotSize);
         }
      }
      else
      {
         int error = GetLastError();
         Print("ERROR al abrir orden de COMPRA. Código: ", error);
         Print("Descripción: ", ErrorDescription(error));

         if(EnableAlerts)
         {
            Alert("ERROR al abrir COMPRA - Código: ", error);
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Execute Sell Order                                               |
//+------------------------------------------------------------------+
void ExecuteSellOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl, OP_SELL);

   if(lotSize > 0)
   {
      int ticket = OrderSend(Symbol(), OP_SELL, lotSize, Bid, Slippage, sl, tp, 
                            Comment_Trades, MagicNumber, 0, clrRed);

      if(ticket > 0)
      {
         tradeExecutedToday = true;
         slMovedToBE = false;

         Print("===== ORDEN DE VENTA EJECUTADA =====");
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
         Print("Precio entrada: ", Bid);
         Print("Stop Loss: ", sl);
         Print("Take Profit: ", tp);
         Print("Riesgo: ", RiskPercent, "% ($", AccountBalance() * RiskPercent / 100, ")");

         if(EnableAlerts)
         {
            Alert("VENTA ejecutada - Ticket: ", ticket, " | Lotes: ", lotSize);
         }
      }
      else
      {
         int error = GetLastError();
         Print("ERROR al abrir orden de VENTA. Código: ", error);
         Print("Descripción: ", ErrorDescription(error));

         if(EnableAlerts)
         {
            Alert("ERROR al abrir VENTA - Código: ", error);
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate Lot Size based on 1% risk                             |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice, int orderType)
{
   double riskAmount = AccountBalance() * RiskPercent / 100.0;
   double slDistance;

   if(orderType == OP_BUY)
      slDistance = Ask - slPrice;
   else
      slDistance = slPrice - Bid;

   if(slDistance <= 0)
   {
      Print("ERROR: SL distance inválida: ", slDistance);
      return 0;
   }

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);

   if(tickValue == 0 || tickSize == 0)
   {
      Print("ERROR: No se pudo obtener tick value o tick size");
      return 0;
   }

   double lotSize = (riskAmount / (slDistance / tickSize * tickValue));

   // Normalizar lote
   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = NormalizeDouble(lotSize, 2);
   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   Print("Lot size calculado: ", lotSize, " (Risk: $", riskAmount, ", SL distance: ", slDistance, ")");

   return lotSize;
}

//+------------------------------------------------------------------+
//| Manage open trades - Move SL to BE at 80% TP                    |
//+------------------------------------------------------------------+
void ManageOpenTrades()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;

      if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
      {
         double openPrice = OrderOpenPrice();
         double sl = OrderStopLoss();
         double tp = OrderTakeProfit();

         if(OrderType() == OP_BUY)
         {
            double distance = tp - openPrice;
            double eightyPercent = openPrice + (distance * 0.8);

            // Si el precio alcanzó el 80% del TP y SL no está en BE
            if(Bid >= eightyPercent && sl < openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("===== SL MOVIDO A BREAKEVEN =====");
                  Print("Ticket: ", OrderTicket());
                  Print("Nuevo SL: ", openPrice);

                  if(EnableAlerts)
                  {
                     Alert("SL movido a BE - Ticket: ", OrderTicket());
                  }
               }
               else
               {
                  Print("ERROR al mover SL a BE. Código: ", GetLastError());
               }
            }
         }
         else if(OrderType() == OP_SELL)
         {
            double distance = openPrice - tp;
            double eightyPercent = openPrice - (distance * 0.8);

            // Si el precio alcanzó el 80% del TP y SL no está en BE
            if(Ask <= eightyPercent && sl > openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("===== SL MOVIDO A BREAKEVEN =====");
                  Print("Ticket: ", OrderTicket());
                  Print("Nuevo SL: ", openPrice);

                  if(EnableAlerts)
                  {
                     Alert("SL movido a BE - Ticket: ", OrderTicket());
                  }
               }
               else
               {
                  Print("ERROR al mover SL a BE. Código: ", GetLastError());
               }
            }
         }
      }
   }
}

