   // Limpiar objetos del día anterior
   ObjectDelete(0, lineHighName);
   ObjectDelete(0, lineLowName);
   ObjectDelete(0, rectName);

   // Verificar si hay noticias hoy
   CheckNewsToday();

   Print("Variables reiniciadas correctamente");
