//+------------------------------------------------------------------+
//| Check for entry conditions (3 velas consecutivas)               |
//+------------------------------------------------------------------+
void CheckForEntry()
{
   // Obtener datos de las últimas 3 velas cerradas
   double open1 = iOpen(Symbol(), PERIOD_M1, 1);
   double close1 = iClose(Symbol(), PERIOD_M1, 1);
   double high1 = iHigh(Symbol(), PERIOD_M1, 1);
   double low1 = iLow(Symbol(), PERIOD_M1, 1);

   double open2 = iOpen(Symbol(), PERIOD_M1, 2);
   double close2 = iClose(Symbol(), PERIOD_M1, 2);
   double high2 = iHigh(Symbol(), PERIOD_M1, 2);
   double low2 = iLow(Symbol(), PERIOD_M1, 2);

   double open3 = iOpen(Symbol(), PERIOD_M1, 3);
   double close3 = iClose(Symbol(), PERIOD_M1, 3);
   double high3 = iHigh(Symbol(), PERIOD_M1, 3);
   double low3 = iLow(Symbol(), PERIOD_M1, 3);

   bool isBullish1 = close1 > open1;
   bool isBullish2 = close2 > open2;
   bool isBullish3 = close3 > open3;

   bool isBearish1 = close1 < open1;
   bool isBearish2 = close2 < open2;
   bool isBearish3 = close3 < open3;

   // CASO COMPRAS: Ruptura alcista
   if(high3 >= rangeHigh && isBullish3 && isBullish2 && isBullish1)
   {
      // Calcular movimiento total de las 3 velas
      double totalMove = CalculatePips(high1 - low3);

      Print("Señal de COMPRA detectada. Movimiento: ", totalMove, " pips");

      if(totalMove <= MaxPipsMove)
      {
         double entryPrice = Ask;
         double sl = low3;
         double slPips = CalculatePips(entryPrice - sl);
         double tp = entryPrice + (entryPrice - sl); // TP = mismo tamaño que SL

         Print("Preparando orden de COMPRA:");
         Print("Entry: ", entryPrice, " | SL: ", sl, " (", slPips, " pips) | TP: ", tp);

         ExecuteBuyOrder(sl, tp);
      }
      else
      {
         Print("ENTRADA ANULADA - Movimiento excede límite: ", totalMove, " pips > ", MaxPipsMove, " pips");
         if(EnableAlerts)
         {
            Alert("Entrada COMPRA anulada - Movimiento excesivo: ", totalMove, " pips");
         }
      }
   }

   // CASO VENTAS: Ruptura bajista
   if(low3 <= rangeLow && isBearish3 && isBearish2 && isBearish1)
   {
      // Calcular movimiento total de las 3 velas
      double totalMove = CalculatePips(high3 - low1);

      Print("Señal de VENTA detectada. Movimiento: ", totalMove, " pips");

      if(totalMove <= MaxPipsMove)
      {
         double entryPrice = Bid;
         double sl = high3;
         double slPips = CalculatePips(sl - entryPrice);
         double tp = entryPrice - (sl - entryPrice); // TP = mismo tamaño que SL

         Print("Preparando orden de VENTA:");
         Print("Entry: ", entryPrice, " | SL: ", sl, " (", slPips, " pips) | TP: ", tp);

         ExecuteSellOrder(sl, tp);
      }
      else
      {
         Print("ENTRADA ANULADA - Movimiento excede límite: ", totalMove, " pips > ", MaxPipsMove, " pips");
         if(EnableAlerts)
         {
            Alert("Entrada VENTA anulada - Movimiento excesivo: ", totalMove, " pips");
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate pips (ajuste para US30)                               |
//+------------------------------------------------------------------+
double CalculatePips(double priceDistance)
{
   double pips = priceDistance / Point;

   // Ajuste para US30 (indices generalmente usan divisor de 10)
   if(StringFind(Symbol(), "US30") >= 0 || StringFind(Symbol(), "DOW") >= 0)
   {
      pips = pips / 10.0;
   }

   return pips;
}

//+------------------------------------------------------------------+
//| Execute Buy Order                                                |
//+------------------------------------------------------------------+
void ExecuteBuyOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl, OP_BUY);

   if(lotSize > 0)
   {
      int ticket = OrderSend(Symbol(), OP_BUY, lotSize, Ask, Slippage, sl, tp, 
                            Comment_Trades, MagicNumber, 0, clrGreen);

      if(ticket > 0)
      {
         tradeExecutedToday = true;
         slMovedToBE = false;

         Print("===== ORDEN DE COMPRA EJECUTADA =====");
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
         Print("Precio entrada: ", Ask);
         Print("Stop Loss: ", sl);
         Print("Take Profit: ", tp);
         Print("Riesgo: ", RiskPercent, "% ($", AccountBalance() * RiskPercent / 100, ")");

         if(EnableAlerts)
         {
            Alert("COMPRA ejecutada - Ticket: ", ticket, " | Lotes: ", lotSize);
         }
      }
      else
      {
         int error = GetLastError();
         Print("ERROR al abrir orden de COMPRA. Código: ", error);
         Print("Descripción: ", ErrorDescription(error));

         if(EnableAlerts)
         {
            Alert("ERROR al abrir COMPRA - Código: ", error);
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Execute Sell Order                                               |
//+------------------------------------------------------------------+
void ExecuteSellOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl, OP_SELL);

   if(lotSize > 0)
   {
      int ticket = OrderSend(Symbol(), OP_SELL, lotSize, Bid, Slippage, sl, tp, 
                            Comment_Trades, MagicNumber, 0, clrRed);

      if(ticket > 0)
      {
         tradeExecutedToday = true;
         slMovedToBE = false;

         Print("===== ORDEN DE VENTA EJECUTADA =====");
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
         Print("Precio entrada: ", Bid);
         Print("Stop Loss: ", sl);
         Print("Take Profit: ", tp);
         Print("Riesgo: ", RiskPercent, "% ($", AccountBalance() * RiskPercent / 100, ")");

         if(EnableAlerts)
         {
            Alert("VENTA ejecutada - Ticket: ", ticket, " | Lotes: ", lotSize);
         }
      }
      else
      {
         int error = GetLastError();
         Print("ERROR al abrir orden de VENTA. Código: ", error);
         Print("Descripción: ", ErrorDescription(error));

         if(EnableAlerts)
         {
            Alert("ERROR al abrir VENTA - Código: ", error);
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate Lot Size based on 1% risk                             |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice, int orderType)
{
   double riskAmount = AccountBalance() * RiskPercent / 100.0;
   double slDistance;

   if(orderType == OP_BUY)
      slDistance = Ask - slPrice;
   else
      slDistance = slPrice - Bid;

   if(slDistance <= 0)
   {
      Print("ERROR: SL distance inválida: ", slDistance);
      return 0;
   }

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);

   if(tickValue == 0 || tickSize == 0)
   {
      Print("ERROR: No se pudo obtener tick value o tick size");
      return 0;
   }

   double lotSize = (riskAmount / (slDistance / tickSize * tickValue));

   // Normalizar lote
   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = NormalizeDouble(lotSize, 2);
   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   Print("Lot size calculado: ", lotSize, " (Risk: $", riskAmount, ", SL distance: ", slDistance, ")");

   return lotSize;
}

//+------------------------------------------------------------------+
//| Manage open trades - Move SL to BE at 80% TP                    |
//+------------------------------------------------------------------+
void ManageOpenTrades()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;

      if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
      {
         double openPrice = OrderOpenPrice();
         double sl = OrderStopLoss();
         double tp = OrderTakeProfit();

         if(OrderType() == OP_BUY)
         {
            double distance = tp - openPrice;
            double eightyPercent = openPrice + (distance * 0.8);

            // Si el precio alcanzó el 80% del TP y SL no está en BE
            if(Bid >= eightyPercent && sl < openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("===== SL MOVIDO A BREAKEVEN =====");
                  Print("Ticket: ", OrderTicket());
                  Print("Nuevo SL: ", openPrice);

                  if(EnableAlerts)
                  {
                     Alert("SL movido a BE - Ticket: ", OrderTicket());
                  }
               }
               else
               {
                  Print("ERROR al mover SL a BE. Código: ", GetLastError());
               }
            }
         }
         else if(OrderType() == OP_SELL)
         {
            double distance = openPrice - tp;
            double eightyPercent = openPrice - (distance * 0.8);

            // Si el precio alcanzó el 80% del TP y SL no está en BE
            if(Ask <= eightyPercent && sl > openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("===== SL MOVIDO A BREAKEVEN =====");
                  Print("Ticket: ", OrderTicket());
                  Print("Nuevo SL: ", openPrice);

                  if(EnableAlerts)
                  {
                     Alert("SL movido a BE - Ticket: ", OrderTicket());
                  }
               }
               else
               {
                  Print("ERROR al mover SL a BE. Código: ", GetLastError());
               }
            }
         }
      }
   }
}

