//+------------------------------------------------------------------+
//| Check for potential entry pattern (primeras 3 velas)            |
//+------------------------------------------------------------------+
void CheckForPotentialEntry()
{
   // Obtener datos de las últimas 3 velas CERRADAS
   double open1 = iOpen(Symbol(), PERIOD_M1, 1);
   double close1 = iClose(Symbol(), PERIOD_M1, 1);
   double high1 = iHigh(Symbol(), PERIOD_M1, 1);
   double low1 = iLow(Symbol(), PERIOD_M1, 1);

   double open2 = iOpen(Symbol(), PERIOD_M1, 2);
   double close2 = iClose(Symbol(), PERIOD_M1, 2);

   double open3 = iOpen(Symbol(), PERIOD_M1, 3);
   double close3 = iClose(Symbol(), PERIOD_M1, 3);
   double high3 = iHigh(Symbol(), PERIOD_M1, 3);
   double low3 = iLow(Symbol(), PERIOD_M1, 3);

   bool isBullish1 = close1 > open1;
   bool isBullish2 = close2 > open2;
   bool isBullish3 = close3 > open3;

   bool isBearish1 = close1 < open1;
   bool isBearish2 = close2 < open2;
   bool isBearish3 = close3 < open3;

   // CASO COMPRAS: Ruptura alcista del máximo del rango
   if(high3 >= rangeHigh && isBullish3 && isBullish2 && isBullish1)
   {
      // Verificar que el movimiento no exceda 200 pips
      double totalMove = CalculatePips(high1 - low3);

      if(totalMove <= MaxPipsMove)
      {
         // MARCAR como señal pendiente - esperar confirmación en vela actual
         pendingBuySignal = true;
         pendingBuySL = low3;
         signalCandleTime = iTime(Symbol(), PERIOD_M1, 0);

         Print("SEÑAL DE COMPRA DETECTADA - Esperando confirmación en vela actual");
         Print("Velas cerradas: Vela[3]=", isBullish3, " Vela[2]=", isBullish2, " Vela[1]=", isBullish1);
         Print("Movimiento: ", totalMove, " pips | SL propuesto: ", pendingBuySL);
      }
      else
      {
         Print("Entrada ANULADA: Movimiento excede ", MaxPipsMove, " pips (", totalMove, " pips)");
      }
   }

   // CASO VENTAS: Ruptura bajista del mínimo del rango
   if(low3 <= rangeLow && isBearish3 && isBearish2 && isBearish1)
   {
      // Verificar que el movimiento no exceda 200 pips
      double totalMove = CalculatePips(high3 - low1);

      if(totalMove <= MaxPipsMove)
      {
         // MARCAR como señal pendiente - esperar confirmación en vela actual
         pendingSellSignal = true;
         pendingSellSL = high3;
         signalCandleTime = iTime(Symbol(), PERIOD_M1, 0);

         Print("SEÑAL DE VENTA DETECTADA - Esperando confirmación en vela actual");
         Print("Velas cerradas: Vela[3]=", isBearish3, " Vela[2]=", isBearish2, " Vela[1]=", isBearish1);
         Print("Movimiento: ", totalMove, " pips | SL propuesto: ", pendingSellSL);
      }
      else
      {
         Print("Entrada ANULADA: Movimiento excede ", MaxPipsMove, " pips (", totalMove, " pips)");
      }
   }
}

//+------------------------------------------------------------------+
//| Check confirmation 5 seconds before candle close                |
//+------------------------------------------------------------------+
void CheckConfirmation5SecondsBefore()
{
   datetime currentCandleTime = iTime(Symbol(), PERIOD_M1, 0);
   datetime nextCandleTime = currentCandleTime + 60; // Próxima vela (60 segundos)
   datetime confirmationTime = nextCandleTime - SecondsBeforeClose; // 5 segundos antes

   datetime currentTime = TimeCurrent();

   // Solo proceder si estamos en la ventana de confirmación (5 segundos antes del cierre)
   if(currentTime < confirmationTime)
   {
      return; // Aún no es el momento de confirmar
   }

   // CONFIRMACIÓN DE COMPRA
   if(pendingBuySignal)
   {
      // Verificar que la vela ACTUAL sigue siendo ALCISTA
      double currentOpen = iOpen(Symbol(), PERIOD_M1, 0);
      double currentClose = iClose(Symbol(), PERIOD_M1, 0);

      bool currentIsBullish = currentClose > currentOpen;

      if(currentIsBullish)
      {
         Print("===== CONFIRMACIÓN DE COMPRA =====");
         Print("Vela actual es ALCISTA 5 segundos antes del cierre");
         Print("Open: ", currentOpen, " Close: ", currentClose);

         // Ejecutar la compra
         double tp = currentClose + (currentClose - pendingBuySL);
         ExecuteBuyOrder(pendingBuySL, tp);

         // Resetear señal
         pendingBuySignal = false;
      }
      else
      {
         Print("COMPRA CANCELADA: Vela actual NO es alcista 5 segundos antes del cierre");
         Print("Open: ", currentOpen, " Close: ", currentClose);
         pendingBuySignal = false;
      }
   }

   // CONFIRMACIÓN DE VENTA
   if(pendingSellSignal)
   {
      // Verificar que la vela ACTUAL sigue siendo BAJISTA
      double currentOpen = iOpen(Symbol(), PERIOD_M1, 0);
      double currentClose = iClose(Symbol(), PERIOD_M1, 0);

      bool currentIsBearish = currentClose < currentOpen;

      if(currentIsBearish)
      {
         Print("===== CONFIRMACIÓN DE VENTA =====");
         Print("Vela actual es BAJISTA 5 segundos antes del cierre");
         Print("Open: ", currentOpen, " Close: ", currentClose);

         // Ejecutar la venta
         double tp = currentClose - (pendingSellSL - currentClose);
         ExecuteSellOrder(pendingSellSL, tp);

         // Resetear señal
         pendingSellSignal = false;
      }
      else
      {
         Print("VENTA CANCELADA: Vela actual NO es bajista 5 segundos antes del cierre");
         Print("Open: ", currentOpen, " Close: ", currentClose);
         pendingSellSignal = false;
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate pips                                                   |
//+------------------------------------------------------------------+
double CalculatePips(double priceDistance)
{
   double pips = priceDistance / Point;

   // Ajuste para US30
   if(StringFind(Symbol(), "US30") >= 0 || StringFind(Symbol(), "DOW") >= 0)
   {
      pips = pips / 10.0;
   }

   return pips;
}

//+------------------------------------------------------------------+
//| Execute Buy Order                                                |
//+------------------------------------------------------------------+
void ExecuteBuyOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl, OP_BUY);

   int ticket = OrderSend(Symbol(), OP_BUY, lotSize, Ask, 3, sl, tp, 
                         "US30 Range Breakout", MagicNumber, 0, clrGreen);

   if(ticket > 0)
   {
      Print("BUY Order opened: Ticket = ", ticket, " Lots = ", lotSize, " SL = ", sl, " TP = ", tp);
      tradeExecutedToday = true;
   }
   else
   {
      Print("Error opening BUY order: ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//| Execute Sell Order                                               |
//+------------------------------------------------------------------+
void ExecuteSellOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl, OP_SELL);

   int ticket = OrderSend(Symbol(), OP_SELL, lotSize, Bid, 3, sl, tp, 
                         "US30 Range Breakout", MagicNumber, 0, clrRed);

   if(ticket > 0)
   {
      Print("SELL Order opened: Ticket = ", ticket, " Lots = ", lotSize, " SL = ", sl, " TP = ", tp);
      tradeExecutedToday = true;
   }
   else
   {
      Print("Error opening SELL order: ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//| Calculate Lot Size based on risk percentage                      |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice, int orderType)
{
   double riskAmount = AccountBalance() * RiskPercent / 100.0;
   double slDistance;

   if(orderType == OP_BUY)
      slDistance = Ask - slPrice;
   else
      slDistance = slPrice - Bid;

   if(slDistance <= 0)
   {
      Print("ERROR: SL distance inválida: ", slDistance);
      return 0;
   }

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);

   if(tickValue == 0 || tickSize == 0)
   {
      Print("ERROR: No se pudo obtener tick value o tick size");
      return 0;
   }

   double lotSize = (riskAmount / (slDistance / tickSize * tickValue));

   // Normalizar lote
   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   return lotSize;
}

//+------------------------------------------------------------------+
//| Manage open trades (move SL to BE at 80% TP)                    |
//+------------------------------------------------------------------+
void ManageOpenTrades()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(OrderSelect(i, SELECT_BY_POS, MODE_TRADES))
      {
         if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
         {
            double openPrice = OrderOpenPrice();
            double sl = OrderStopLoss();
            double tp = OrderTakeProfit();

            if(OrderType() == OP_BUY)
            {
               double distance = tp - openPrice;
               double eightyPercent = openPrice + (distance * 0.8);

               if(Bid >= eightyPercent && sl < openPrice)
               {
                  bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);
                  if(result)
                     Print("SL moved to BE for BUY order #", OrderTicket());
               }
            }
            else if(OrderType() == OP_SELL)
            {
               double distance = openPrice - tp;
               double eightyPercent = openPrice - (distance * 0.8);

               if(Ask <= eightyPercent && sl > openPrice)
               {
                  bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);
                  if(result)
                     Print("SL moved to BE for SELL order #", OrderTicket());
               }
            }
         }
      }
   }
}

