         Print("Vela actual es ALCISTA 5 segundos antes del cierre");
         Print("Open: ", currentOpen, " Close: ", currentClose);

         // Ejecutar la compra
         double tp = currentClose + (currentClose - pendingBuySL);
         ExecuteBuyOrder(pendingBuySL, tp);

