         pendingSellSignal = false;
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate pips                                                   |
//+------------------------------------------------------------------+
double CalculatePips(double priceDistance)
{
   double pips = priceDistance / Point;

   // Ajuste para US30
   if(StringFind(Symbol(), "US30") >= 0 || StringFind(Symbol(), "DOW") >= 0)
   {
      pips = pips / 10.0;
   }

   return pips;
}

//+------------------------------------------------------------------+
//| Execute Buy Order                                                |
//+------------------------------------------------------------------+
void ExecuteBuyOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl, OP_BUY);

   int ticket = OrderSend(Symbol(), OP_BUY, lotSize, Ask, 3, sl, tp, 
                         "US30 Range Breakout", MagicNumber, 0, clrGreen);

   if(ticket > 0)
   {
      Print("BUY Order opened: Ticket = ", ticket, " Lots = ", lotSize, " SL = ", sl, " TP = ", tp);
      tradeExecutedToday = true;
   }
   else
   {
      Print("Error opening BUY order: ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//| Execute Sell Order                                               |
//+------------------------------------------------------------------+
void ExecuteSellOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl, OP_SELL);

   int ticket = OrderSend(Symbol(), OP_SELL, lotSize, Bid, 3, sl, tp, 
                         "US30 Range Breakout", MagicNumber, 0, clrRed);

   if(ticket > 0)
   {
      Print("SELL Order opened: Ticket = ", ticket, " Lots = ", lotSize, " SL = ", sl, " TP = ", tp);
      tradeExecutedToday = true;
   }
   else
   {
      Print("Error opening SELL order: ", GetLastError());
   }
}

//+------------------------------------------------------------------+
//| Calculate Lot Size based on risk percentage                      |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice, int orderType)
{
   double riskAmount = AccountBalance() * RiskPercent / 100.0;
   double slDistance;

   if(orderType == OP_BUY)
      slDistance = Ask - slPrice;
   else
      slDistance = slPrice - Bid;

   if(slDistance <= 0)
   {
      Print("ERROR: SL distance inválida: ", slDistance);
      return 0;
   }

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);

   if(tickValue == 0 || tickSize == 0)
   {
      Print("ERROR: No se pudo obtener tick value o tick size");
      return 0;
   }

   double lotSize = (riskAmount / (slDistance / tickSize * tickValue));

   // Normalizar lote
   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   return lotSize;
}

//+------------------------------------------------------------------+
//| Manage open trades (move SL to BE at 80% TP)                    |
//+------------------------------------------------------------------+
void ManageOpenTrades()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(OrderSelect(i, SELECT_BY_POS, MODE_TRADES))
      {
         if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
         {
            double openPrice = OrderOpenPrice();
            double sl = OrderStopLoss();
            double tp = OrderTakeProfit();

            if(OrderType() == OP_BUY)
            {
               double distance = tp - openPrice;
               double eightyPercent = openPrice + (distance * 0.8);

               if(Bid >= eightyPercent && sl < openPrice)
               {
                  bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);
                  if(result)
                     Print("SL moved to BE for BUY order #", OrderTicket());
               }
            }
            else if(OrderType() == OP_SELL)
            {
               double distance = openPrice - tp;
               double eightyPercent = openPrice - (distance * 0.8);

               if(Ask <= eightyPercent && sl > openPrice)
               {
                  bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);
                  if(result)
                     Print("SL moved to BE for SELL order #", OrderTicket());
               }
            }
         }
      }
   }
}

