   double close3 = iClose(Symbol(), PERIOD_M1, 3);
   double high3 = iHigh(Symbol(), PERIOD_M1, 3);
   double low3 = iLow(Symbol(), PERIOD_M1, 3);

   bool isBullish1 = close1 > open1;
   bool isBullish2 = close2 > open2;
   bool isBullish3 = close3 > open3;

   bool isBearish1 = close1 < open1;
   bool isBearish2 = close2 < open2;
   bool isBearish3 = close3 < open3;

   // CASO COMPRAS: Ruptura alcista
   if(high3 >= rangeHigh && isBullish3 && isBullish2 && isBullish1)
   {
      // Calcular movimiento total de las 3 velas
      double totalMove = CalculatePips(high1 - low3);

      Print("PATRÓN DE COMPRA DETECTADO - Movimiento: ", totalMove, " pips");

      if(totalMove <= MaxPipsMove)
      {
         // MARCAR como señal pendiente - esperar confirmación en vela actual
         pendingBuySignal = true;
         pendingBuySL = low3;
         signalCandleTime = iTime(Symbol(), PERIOD_M1, 0);

         Print("===== SEÑAL DE COMPRA PENDIENTE =====");
         Print("Esperando confirmación en vela actual (", SecondsBeforeClose, " seg antes del cierre)");
         Print("Velas cerradas confirmadas: [3]=Alcista, [2]=Alcista, [1]=Alcista");
         Print("SL propuesto: ", pendingBuySL);
