//+------------------------------------------------------------------+
//| Calculate Lot Size - RIESGO FIJO $100                           |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice, int orderType)
{
   double slDistance;

   if(orderType == OP_BUY)
      slDistance = Ask - slPrice;
   else
      slDistance = slPrice - Bid;

   if(slDistance <= 0)
   {
      Print("ERROR: SL distance inválida");
      return 0;
   }

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);

   if(tickValue == 0 || tickSize == 0)
   {
      Print("ERROR: Tick value/size inválidos");
      return 0;
   }

   // Cálculo con riesgo fijo
   double lotSize = (RiskAmount / (slDistance / tickSize * tickValue));

   // Normalizar
   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = NormalizeDouble(lotSize, 2);
   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   return lotSize;
}

