//+------------------------------------------------------------------+
//| Detect setup - Verificar condiciones de 3 velas                 |
//+------------------------------------------------------------------+
void DetectSetup()
{
   // Velas cerradas
   double open2 = iOpen(Symbol(), PERIOD_M1, 2);
   double close2 = iClose(Symbol(), PERIOD_M1, 2);
   double high2 = iHigh(Symbol(), PERIOD_M1, 2);
   double low2 = iLow(Symbol(), PERIOD_M1, 2);

   double open3 = iOpen(Symbol(), PERIOD_M1, 3);
   double close3 = iClose(Symbol(), PERIOD_M1, 3);
   double high3 = iHigh(Symbol(), PERIOD_M1, 3);
   double low3 = iLow(Symbol(), PERIOD_M1, 3);

   // Vela actual (vela 1, la tercera del setup)
   double open1 = iOpen(Symbol(), PERIOD_M1, 0);
   double close1 = iClose(Symbol(), PERIOD_M1, 0); // Precio actual
   double high1 = iHigh(Symbol(), PERIOD_M1, 0);
   double low1 = iLow(Symbol(), PERIOD_M1, 0);

   bool isBullish2 = close2 > open2;
   bool isBullish3 = close3 > open3;
   bool isBullish1 = close1 > open1; // Vela actual

   bool isBearish2 = close2 < open2;
   bool isBearish3 = close3 < open3;
   bool isBearish1 = close1 < open1; // Vela actual

   // SETUP DE COMPRA
   // Vela 3 rompe máximo y es alcista
   // Vela 2 es alcista
   // Vela 1 (actual) debe ser alcista también
   if(high3 >= rangeHigh && isBullish3 && isBullish2 && isBullish1)
   {
      double totalMove = CalculatePips(high1 - low3);

      if(totalMove <= MaxPipsMove)
      {
         if(!setupActive || setupType != 1)
         {
            setupActive = true;
            setupType = 1; // Compra
            setupSL = low3;
            setupStartTime = iTime(Symbol(), PERIOD_M1, 0);
            entryExecuted = false;

            Print("SETUP COMPRA activado. Esperando entrada en 5 seg antes del cierre");

            if(EnableAlerts)
            {
               Alert("Setup COMPRA detectado - Esperando entrada");
            }
         }
      }
      else
      {
         if(setupActive && setupType == 1)
         {
            Print("Setup COMPRA anulado - Movimiento excesivo: ", totalMove, " pips");
            setupActive = false;
         }
      }
   }
   else if(setupActive && setupType == 1)
   {
      // Si la vela actual dejó de ser alcista, cancelar setup
      if(!isBullish1)
      {
         Print("Setup COMPRA cancelado - Vela actual no es alcista");
         setupActive = false;
      }
   }

   // SETUP DE VENTA
   // Vela 3 rompe mínimo y es bajista
   // Vela 2 es bajista
   // Vela 1 (actual) debe ser bajista también
   if(low3 <= rangeLow && isBearish3 && isBearish2 && isBearish1)
   {
      double totalMove = CalculatePips(high3 - low1);

      if(totalMove <= MaxPipsMove)
      {
         if(!setupActive || setupType != -1)
         {
            setupActive = true;
            setupType = -1; // Venta
            setupSL = high3;
            setupStartTime = iTime(Symbol(), PERIOD_M1, 0);
            entryExecuted = false;

            Print("SETUP VENTA activado. Esperando entrada en 5 seg antes del cierre");

            if(EnableAlerts)
            {
               Alert("Setup VENTA detectado - Esperando entrada");
            }
         }
      }
      else
      {
         if(setupActive && setupType == -1)
         {
            Print("Setup VENTA anulado - Movimiento excesivo: ", totalMove, " pips");
            setupActive = false;
         }
      }
   }
   else if(setupActive && setupType == -1)
   {
      // Si la vela actual dejó de ser bajista, cancelar setup
      if(!isBearish1)
      {
         Print("Setup VENTA cancelado - Vela actual no es bajista");
         setupActive = false;
      }
   }
}

//+------------------------------------------------------------------+
//| Execute entry if timing is correct                              |
//+------------------------------------------------------------------+
void ExecuteEntryIfTiming()
{
   if(!setupActive || entryExecuted) return;

   datetime currentCandleTime = iTime(Symbol(), PERIOD_M1, 0);
   datetime currentTime = TimeCurrent();

   // Calcular tiempo restante hasta el cierre de la vela
   datetime nextCandleTime = currentCandleTime + 60; // Próxima vela en 60 segundos
   int secondsUntilClose = (int)(nextCandleTime - currentTime);

   // Ejecutar cuando falten exactamente EntrySecondsBeforeClose segundos (o menos)
   if(secondsUntilClose <= EntrySecondsBeforeClose && secondsUntilClose > 0)
   {
      // Verificar una última vez que la vela sigue siendo válida
      double open1 = iOpen(Symbol(), PERIOD_M1, 0);
      double close1 = iClose(Symbol(), PERIOD_M1, 0);

      bool isStillBullish = close1 > open1;
      bool isStillBearish = close1 < open1;

      if(setupType == 1 && isStillBullish) // Setup de compra
      {
         double entryPrice = Ask;
         double sl = setupSL;
         double tp = entryPrice + (entryPrice - sl);

         Print("===== EJECUTANDO COMPRA - ", secondsUntilClose, " seg antes del cierre =====");
         ExecuteBuyOrder(sl, tp);
         entryExecuted = true;
      }
      else if(setupType == -1 && isStillBearish) // Setup de venta
      {
         double entryPrice = Bid;
         double sl = setupSL;
         double tp = entryPrice - (sl - entryPrice);

         Print("===== EJECUTANDO VENTA - ", secondsUntilClose, " seg antes del cierre =====");
         ExecuteSellOrder(sl, tp);
         entryExecuted = true;
      }
      else
      {
         Print("Setup cancelado - Vela cambió de dirección antes de la entrada");
         setupActive = false;
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate pips                                                   |
//+------------------------------------------------------------------+
double CalculatePips(double priceDistance)
{
   double pips = priceDistance / Point;

   if(StringFind(Symbol(), "US30") >= 0 || StringFind(Symbol(), "DOW") >= 0)
   {
      pips = pips / 10.0;
   }

   return pips;
}

//+------------------------------------------------------------------+
//| Execute Buy Order                                                |
//+------------------------------------------------------------------+
void ExecuteBuyOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl, OP_BUY);

   if(lotSize > 0)
   {
      int ticket = OrderSend(Symbol(), OP_BUY, lotSize, Ask, Slippage, sl, tp, 
                            "US30_5Sec", MagicNumber, 0, clrGreen);

      if(ticket > 0)
      {
         tradeExecutedToday = true;
         slMovedToBE = false;
         setupActive = false;

         Print("===== COMPRA EJECUTADA =====");
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
         Print("Entry: ", Ask, " | SL: ", sl, " | TP: ", tp);

         if(EnableAlerts)
         {
            Alert("COMPRA ejecutada - Ticket: ", ticket);
         }
      }
      else
      {
         int error = GetLastError();
         Print("ERROR al abrir COMPRA: ", error);
         if(EnableAlerts)
         {
            Alert("ERROR COMPRA: ", error);
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Execute Sell Order                                               |
//+------------------------------------------------------------------+
void ExecuteSellOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl, OP_SELL);

   if(lotSize > 0)
   {
      int ticket = OrderSend(Symbol(), OP_SELL, lotSize, Bid, Slippage, sl, tp, 
                            "US30_5Sec", MagicNumber, 0, clrRed);

      if(ticket > 0)
      {
         tradeExecutedToday = true;
         slMovedToBE = false;
         setupActive = false;

         Print("===== VENTA EJECUTADA =====");
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
         Print("Entry: ", Bid, " | SL: ", sl, " | TP: ", tp);

         if(EnableAlerts)
         {
            Alert("VENTA ejecutada - Ticket: ", ticket);
         }
      }
      else
      {
         int error = GetLastError();
         Print("ERROR al abrir VENTA: ", error);
         if(EnableAlerts)
         {
            Alert("ERROR VENTA: ", error);
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate Lot Size - RIESGO FIJO                                |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice, int orderType)
{
   double slDistance;

   if(orderType == OP_BUY)
      slDistance = Ask - slPrice;
   else
      slDistance = slPrice - Bid;

   if(slDistance <= 0)
   {
      Print("ERROR: SL distance inválida");
      return 0;
   }

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);

   if(tickValue == 0 || tickSize == 0)
   {
      Print("ERROR: Tick value/size inválidos");
      return 0;
   }

   double lotSize = (RiskAmount / (slDistance / tickSize * tickValue));

   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = NormalizeDouble(lotSize, 2);
   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   return lotSize;
}

//+------------------------------------------------------------------+
//| Manage open trades                                               |
//+------------------------------------------------------------------+
void ManageOpenTrades()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;

      if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
      {
         double openPrice = OrderOpenPrice();
         double sl = OrderStopLoss();
         double tp = OrderTakeProfit();

         if(OrderType() == OP_BUY)
         {
            double distance = tp - openPrice;
            double eightyPercent = openPrice + (distance * 0.8);

            if(Bid >= eightyPercent && sl < openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("SL movido a BE - Ticket: ", OrderTicket());

                  if(EnableAlerts)
                  {
                     Alert("SL en BE - Ticket: ", OrderTicket());
                  }
               }
            }
         }
         else if(OrderType() == OP_SELL)
         {
            double distance = openPrice - tp;
            double eightyPercent = openPrice - (distance * 0.8);

            if(Ask <= eightyPercent && sl > openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("SL movido a BE - Ticket: ", OrderTicket());

                  if(EnableAlerts)
                  {
                     Alert("SL en BE - Ticket: ", OrderTicket());
                  }
               }
            }
         }
      }
   }
}

