//+------------------------------------------------------------------+
//| Expert deinitialization function                                 |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   ObjectDelete(0, "RangeHigh");
   ObjectDelete(0, "RangeLow");
   ObjectDelete(0, "TradingWindow");
   Comment("");

   Print("EA detenido. Razón: ", reason);
}

//+------------------------------------------------------------------+
//| Expert tick function                                             |
//+------------------------------------------------------------------+
void OnTick()
{
   // Verificar si es un nuevo día
   if(TimeDayOfYear(TimeCurrent()) != TimeDayOfYear(lastTradeDate))
   {
      ResetDaily();
   }

   // Obtener hora actual (hora del servidor)
   datetime currentTime = TimeCurrent();
   int currentHour = TimeHour(currentTime);
   int currentMinute = TimeMinute(currentTime);

   // PASO #1: Establecer rango entre 4:00 AM - 9:00 AM
   if(currentHour >= 4 && currentHour < 9)
   {
      UpdateRange();
   }

   // Finalizar establecimiento del rango a las 9:00 AM
   if(currentHour == 9 && currentMinute == 0 && !rangeSet)
   {
      FinalizeRange();
   }

   // PASO #2: Ventana de trading 9:30 AM - 12:15 PM
   tradingWindowActive = false;
   if((currentHour == 9 && currentMinute >= 30) || 
      (currentHour > 9 && currentHour < 12) ||
      (currentHour == 12 && currentMinute <= 15))
   {
      tradingWindowActive = true;

      // Verificar filtro de noticias
      if(UseNewsFilter && newsEventToday && currentTime < newsEventTime)
      {
         tradingWindowActive = false;
         Comment("Esperando finalización de noticias...\nNoticias programadas: ", 
                 TimeToString(newsEventTime, TIME_MINUTES));
         return;
      }
   }

   // Verificar nueva vela en M1
   datetime currentCandleTime = iTime(Symbol(), PERIOD_M1, 0);
   if(currentCandleTime != lastCandleTime)
   {
      lastCandleTime = currentCandleTime;

      // PASO #3: Ejecutar lógica de trading al cierre de cada vela
      if(tradingWindowActive && rangeSet && !tradeExecutedToday)
      {
         CheckForEntry();
      }
   }

   // PASO #4: Gestión de trades abiertos (mover SL a BE al 80% del TP)
   ManageOpenTrades();

   // Actualizar información en pantalla
   UpdateDisplay();
}

//+------------------------------------------------------------------+
//| Reset daily variables                                            |
//+------------------------------------------------------------------+
void ResetDaily()
{
   Print("===== NUEVO DÍA DE TRADING =====");
   Print("Fecha: ", TimeToString(TimeCurrent(), TIME_DATE));

   lastTradeDate = TimeCurrent();
   rangeHigh = 0;
   rangeLow = 999999;
   rangeSet = false;
   tradingWindowActive = false;
   tradeExecutedToday = false;
   slMovedToBE = false;

   // Limpiar objetos del día anterior
   ObjectDelete(0, "RangeHigh");
   ObjectDelete(0, "RangeLow");
   ObjectDelete(0, "TradingWindow");

   // Verificar si hay noticias hoy
   CheckNewsToday();

   Print("Variables reiniciadas correctamente");
}

//+------------------------------------------------------------------+
//| Update range during 4:00 AM - 9:00 AM                           |
//+------------------------------------------------------------------+
void UpdateRange()
{
   for(int i = 1; i < 300; i++) // Revisar últimas 5 horas (300 velas M1)
   {
      datetime barTime = iTime(Symbol(), PERIOD_M1, i);
      int barHour = TimeHour(barTime);

      if(barHour >= 4 && barHour < 9)
      {
         double high = iHigh(Symbol(), PERIOD_M1, i);
         double low = iLow(Symbol(), PERIOD_M1, i);

         if(high > rangeHigh) rangeHigh = high;
         if(low < rangeLow) rangeLow = low;
      }
   }
}

//+------------------------------------------------------------------+
//| Finalize range at 9:00 AM                                       |
//+------------------------------------------------------------------+
void FinalizeRange()
{
   if(rangeHigh > 0 && rangeLow < 999999)
   {
      rangeSet = true;
      Print("===== RANGO ESTABLECIDO =====");
      Print("Range High: ", rangeHigh);
      Print("Range Low: ", rangeLow);
      Print("Range Size: ", CalculatePips(rangeHigh - rangeLow), " pips");

      // Dibujar líneas horizontales
      DrawRangeLines();

      if(EnableAlerts)
      {
         Alert("Rango establecido - High: ", rangeHigh, " Low: ", rangeLow);
      }
   }
   else
   {
      Print("ERROR: No se pudo establecer el rango correctamente");
   }
}

//+------------------------------------------------------------------+
