//+------------------------------------------------------------------+
//| Check for entry conditions - LÓGICA CORRECTA                    |
//| Vela 3: Primera vela que rompe el rango                         |
//| Vela 2: Segunda vela alcista/bajista                            |
//| Vela 1: Tercera vela alcista/bajista → ENTRADA                  |
//+------------------------------------------------------------------+
void CheckForEntry()
{
   // Obtener datos de las últimas 3 velas CERRADAS
   double open1 = iOpen(Symbol(), PERIOD_M1, 1);   // Vela recién cerrada (tercera del setup)
   double close1 = iClose(Symbol(), PERIOD_M1, 1);
   double high1 = iHigh(Symbol(), PERIOD_M1, 1);
   double low1 = iLow(Symbol(), PERIOD_M1, 1);

   double open2 = iOpen(Symbol(), PERIOD_M1, 2);   // Hace 2 velas (segunda del setup)
   double close2 = iClose(Symbol(), PERIOD_M1, 2);
   double high2 = iHigh(Symbol(), PERIOD_M1, 2);
   double low2 = iLow(Symbol(), PERIOD_M1, 2);

   double open3 = iOpen(Symbol(), PERIOD_M1, 3);   // Hace 3 velas (primera del setup - la que rompe)
   double close3 = iClose(Symbol(), PERIOD_M1, 3);
   double high3 = iHigh(Symbol(), PERIOD_M1, 3);
   double low3 = iLow(Symbol(), PERIOD_M1, 3);

   bool isBullish1 = close1 > open1;
   bool isBullish2 = close2 > open2;
   bool isBullish3 = close3 > open3;

   bool isBearish1 = close1 < open1;
   bool isBearish2 = close2 < open2;
   bool isBearish3 = close3 < open3;

   // CASO COMPRAS
   // Vela 3: Toca/rompe el máximo del rango Y es alcista
   // Vela 2: Es alcista
   // Vela 1: Es alcista → ENTRADA
   if(high3 >= rangeHigh && isBullish3 && isBullish2 && isBullish1)
   {
      // Calcular movimiento total de las 3 velas
      double totalMove = CalculatePips(high1 - low3);

      Print("===== SEÑAL DE COMPRA DETECTADA =====");
      Print("Vela 3 (primera): High=", high3, " rompió rangeHigh=", rangeHigh);
      Print("Vela 2 (segunda): Alcista");
      Print("Vela 1 (tercera): Alcista");
      Print("Movimiento total: ", totalMove, " pips");

      if(totalMove <= MaxPipsMove)
      {
         double entryPrice = Ask;
         double sl = low3;  // SL en el mínimo de la vela que rompió
         double slPips = CalculatePips(entryPrice - sl);
         double tp = entryPrice + (entryPrice - sl); // TP = misma distancia que SL

         Print("Preparando orden de COMPRA:");
         Print("Entry: ", entryPrice, " | SL: ", sl, " (", slPips, " pips) | TP: ", tp);

         ExecuteBuyOrder(sl, tp);
      }
      else
      {
         Print("===== ENTRADA ANULADA =====");
         Print("Movimiento excede límite: ", totalMove, " pips > ", MaxPipsMove, " pips");
         if(EnableAlerts)
         {
            Alert("Entrada COMPRA anulada - Movimiento excesivo: ", totalMove, " pips");
         }
      }
   }

   // CASO VENTAS
   // Vela 3: Toca/rompe el mínimo del rango Y es bajista
   // Vela 2: Es bajista
   // Vela 1: Es bajista → ENTRADA
   if(low3 <= rangeLow && isBearish3 && isBearish2 && isBearish1)
   {
      // Calcular movimiento total de las 3 velas
      double totalMove = CalculatePips(high3 - low1);

      Print("===== SEÑAL DE VENTA DETECTADA =====");
      Print("Vela 3 (primera): Low=", low3, " rompió rangeLow=", rangeLow);
      Print("Vela 2 (segunda): Bajista");
      Print("Vela 1 (tercera): Bajista");
      Print("Movimiento total: ", totalMove, " pips");

      if(totalMove <= MaxPipsMove)
      {
         double entryPrice = Bid;
         double sl = high3;  // SL en el máximo de la vela que rompió
         double slPips = CalculatePips(sl - entryPrice);
         double tp = entryPrice - (sl - entryPrice); // TP = misma distancia que SL

         Print("Preparando orden de VENTA:");
         Print("Entry: ", entryPrice, " | SL: ", sl, " (", slPips, " pips) | TP: ", tp);

         ExecuteSellOrder(sl, tp);
      }
      else
      {
         Print("===== ENTRADA ANULADA =====");
         Print("Movimiento excede límite: ", totalMove, " pips > ", MaxPipsMove, " pips");
         if(EnableAlerts)
         {
            Alert("Entrada VENTA anulada - Movimiento excesivo: ", totalMove, " pips");
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate pips (ajuste para US30)                               |
//+------------------------------------------------------------------+
double CalculatePips(double priceDistance)
{
   double pips = priceDistance / Point;

   // Ajuste para US30 (indices generalmente usan divisor de 10)
   if(StringFind(Symbol(), "US30") >= 0 || StringFind(Symbol(), "DOW") >= 0)
   {
      pips = pips / 10.0;
   }

   return pips;
}

