//+------------------------------------------------------------------+
//| Calculate Lot Size - RIESGO FIJO $100                           |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice, int orderType)
{
   double slDistance;

   if(orderType == OP_BUY)
      slDistance = Ask - slPrice;
   else
      slDistance = slPrice - Bid;

   if(slDistance <= 0)
   {
      Print("ERROR: SL distance inválida: ", slDistance);
      return 0;
   }

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);

   if(tickValue == 0 || tickSize == 0)
   {
      Print("ERROR: No se pudo obtener tick value o tick size");
      return 0;
   }

   // Calcular lotes para arriesgar exactamente RiskAmount ($100)
   double lotSize = (RiskAmount / (slDistance / tickSize * tickValue));

   // Normalizar lote
   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = NormalizeDouble(lotSize, 2);
   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   Print("Lot size calculado: ", lotSize, " (Risk: $", RiskAmount, ", SL distance: ", CalculatePips(slDistance), " pips)");

   return lotSize;
}

//+------------------------------------------------------------------+
//| Manage open trades - Move SL to BE at 80% TP                    |
//+------------------------------------------------------------------+
void ManageOpenTrades()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;

      if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
      {
         double openPrice = OrderOpenPrice();
         double sl = OrderStopLoss();
         double tp = OrderTakeProfit();

         if(OrderType() == OP_BUY)
         {
            double distance = tp - openPrice;
            double eightyPercent = openPrice + (distance * 0.8);

            // Si el precio alcanzó el 80% del TP y SL no está en BE
            if(Bid >= eightyPercent && sl < openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("===== SL MOVIDO A BREAKEVEN =====");
                  Print("Ticket: ", OrderTicket());
                  Print("Nuevo SL: ", openPrice);

                  if(EnableAlerts)
                  {
                     Alert("SL movido a BE - Ticket: ", OrderTicket());
                  }
               }
               else
               {
                  Print("ERROR al mover SL a BE. Código: ", GetLastError());
               }
            }
         }
         else if(OrderType() == OP_SELL)
         {
            double distance = openPrice - tp;
            double eightyPercent = openPrice - (distance * 0.8);

            // Si el precio alcanzó el 80% del TP y SL no está en BE
            if(Ask <= eightyPercent && sl > openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("===== SL MOVIDO A BREAKEVEN =====");
                  Print("Ticket: ", OrderTicket());
                  Print("Nuevo SL: ", openPrice);

                  if(EnableAlerts)
                  {
                     Alert("SL movido a BE - Ticket: ", OrderTicket());
                  }
               }
               else
               {
                  Print("ERROR al mover SL a BE. Código: ", GetLastError());
               }
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Check if there are news events today                            |
//+------------------------------------------------------------------+
void CheckNewsToday()
{
   if(!UseNewsFilter)
   {
      newsEventToday = false;
      return;
   }

   // Configurar hora de noticias
   string todayDate = TimeToString(TimeCurrent(), TIME_DATE);
   newsEventTime = StrToTime(todayDate + " " + NewsTime);
   newsEventToday = true;

   Print("Filtro de noticias activo. Noticias programadas: ", TimeToString(newsEventTime));
}

