//+------------------------------------------------------------------+
//| Error description                                                |
//+------------------------------------------------------------------+
string ErrorDescription(int errorCode)
{
   string errorString;

   switch(errorCode)
   {
      case 0:    errorString="Sin error";break;
      case 130:  errorString="Stops inválidos";break;
      case 131:  errorString="Volumen inválido";break;
      case 132:  errorString="Mercado cerrado";break;
      case 133:  errorString="Trading deshabilitado";break;
      case 134:  errorString="Fondos insuficientes";break;
      case 135:  errorString="Precio cambió";break;
      case 136:  errorString="Sin precios";break;
      case 138:  errorString="Nuevo precio";break;
      case 139:  errorString="Orden bloqueada";break;
      case 148:  errorString="Demasiadas órdenes";break;
      default:   errorString="Error " + IntegerToString(errorCode);
   }

   return errorString;
}
