//+------------------------------------------------------------------+
//|                     US30_Range_Breakout_Fixed_UTC.mq4           |
//|                     VERSIÓN CORREGIDA - TRACKING DE RUPTURA      |
//|                     Horario UTC                                  |
//+------------------------------------------------------------------+
#property copyright "Trading Strategy Automation"
#property link      ""
#property version   "4.00"
#property strict

//--- Input parameters
input double RiskAmount = 100.0;          // Riesgo fijo por operación ($)
input int    MaxPipsMove = 200;           // Máximo movimiento en pips
input int    MagicNumber = 123456;        // Número mágico único
input bool   EnableAlerts = true;         // Habilitar alertas
input bool   UseNewsFilter = true;        // Filtro de noticias
input string NewsTime = "15:00";          // Hora de noticias UTC
input int    Slippage = 3;                // Slippage permitido

//--- Global variables
datetime lastTradeDate = 0;
double   rangeHigh = 0;
double   rangeLow = 0;
bool     rangeSet = false;
bool     tradingWindowActive = false;
bool     tradeExecutedToday = false;
bool     newsEventToday = false;
datetime newsEventTime = 0;
bool     slMovedToBE = false;
datetime lastCandleTime = 0;

// Variables para tracking de ruptura
bool     breakoutDetected = false;
datetime breakoutCandleTime = 0;
int      breakoutType = 0;  // 1 = alcista (compra), -1 = bajista (venta)
double   breakoutSL = 0;
int      candlesAfterBreakout = 0;

//+------------------------------------------------------------------+
//| Expert initialization function                                   |
//+------------------------------------------------------------------+
int OnInit()
{
   Print("==================================================");
   Print("US30 Range Breakout - FIXED VERSION - UTC");
   Print("==================================================");
   Print("HORARIOS EN UTC (GMT+0)");
   Print("Rango: 9:00 - 14:00 UTC");
   Print("Trading: 14:30 - 17:15 UTC");
   Print("Riesgo fijo: $", RiskAmount);
   Print("==================================================");

   if(Period() != PERIOD_M1)
   {
      Alert("ADVERTENCIA: Este EA debe ejecutarse en M1");
   }

   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Expert deinitialization function                                 |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   ObjectDelete(0, "RangeHigh");
   ObjectDelete(0, "RangeLow");
   ObjectDelete(0, "TradingWindow");
   ObjectDelete(0, "BreakoutCandle");
   Comment("");
}

//+------------------------------------------------------------------+
//| Expert tick function                                             |
//+------------------------------------------------------------------+
void OnTick()
{
   // Verificar nuevo día
   if(TimeDayOfYear(TimeCurrent()) != TimeDayOfYear(lastTradeDate))
   {
      ResetDaily();
   }

   datetime currentTime = TimeCurrent();
   int currentHour = TimeHour(currentTime);
   int currentMinute = TimeMinute(currentTime);

   // PASO #1: Establecer rango 9:00 - 14:00 UTC
   if(currentHour >= 9 && currentHour < 14)
   {
      UpdateRange();
   }

   // Finalizar rango a las 14:00 UTC
   if(currentHour == 14 && currentMinute == 0 && !rangeSet)
   {
      FinalizeRange();
   }

   // PASO #2: Ventana de trading 14:30 - 17:15 UTC
   tradingWindowActive = false;
   if((currentHour == 14 && currentMinute >= 30) || 
      (currentHour > 14 && currentHour < 17) ||
      (currentHour == 17 && currentMinute <= 15))
   {
      tradingWindowActive = true;

      if(UseNewsFilter && newsEventToday && currentTime < newsEventTime)
      {
         tradingWindowActive = false;
         return;
      }
   }

   // Verificar nueva vela
   datetime currentCandleTime = iTime(Symbol(), PERIOD_M1, 0);
   if(currentCandleTime != lastCandleTime)
   {
      lastCandleTime = currentCandleTime;

      // PASO #3: Lógica de entrada con tracking
      if(tradingWindowActive && rangeSet && !tradeExecutedToday)
      {
         ProcessNewCandle();
      }
   }

   // PASO #4: Gestión de trades
   ManageOpenTrades();

   UpdateDisplay();
}

//+------------------------------------------------------------------+
//| Reset daily variables                                            |
//+------------------------------------------------------------------+
void ResetDaily()
{
   Print("===== NUEVO DÍA =====");
   Print("Fecha: ", TimeToString(TimeCurrent(), TIME_DATE));

   lastTradeDate = TimeCurrent();
   rangeHigh = 0;
   rangeLow = 999999;
   rangeSet = false;
   tradingWindowActive = false;
   tradeExecutedToday = false;
   slMovedToBE = false;

   // Reset tracking variables
   breakoutDetected = false;
   breakoutCandleTime = 0;
   breakoutType = 0;
   breakoutSL = 0;
   candlesAfterBreakout = 0;

   ObjectDelete(0, "RangeHigh");
   ObjectDelete(0, "RangeLow");
   ObjectDelete(0, "TradingWindow");
   ObjectDelete(0, "BreakoutCandle");

   CheckNewsToday();
}

//+------------------------------------------------------------------+
//| Update range                                                     |
//+------------------------------------------------------------------+
void UpdateRange()
{
   for(int i = 1; i < 300; i++)
   {
      datetime barTime = iTime(Symbol(), PERIOD_M1, i);
      int barHour = TimeHour(barTime);

      if(barHour >= 9 && barHour < 14)
      {
         double high = iHigh(Symbol(), PERIOD_M1, i);
         double low = iLow(Symbol(), PERIOD_M1, i);

         if(high > rangeHigh) rangeHigh = high;
         if(low < rangeLow) rangeLow = low;
      }
   }
}

//+------------------------------------------------------------------+
//| Finalize range                                                   |
//+------------------------------------------------------------------+
void FinalizeRange()
{
   if(rangeHigh > 0 && rangeLow < 999999)
   {
      rangeSet = true;
      Print("===== RANGO ESTABLECIDO =====");
      Print("Range High: ", rangeHigh);
      Print("Range Low: ", rangeLow);
      Print("Range Size: ", CalculatePips(rangeHigh - rangeLow), " pips");

      DrawRangeLines();

      if(EnableAlerts)
      {
         Alert("Rango establecido - High: ", rangeHigh, " Low: ", rangeLow);
      }
   }
}

//+------------------------------------------------------------------+
//| Draw range lines                                                 |
//+------------------------------------------------------------------+
void DrawRangeLines()
{
   ObjectDelete(0, "RangeHigh");
   ObjectCreate(0, "RangeHigh", OBJ_HLINE, 0, 0, rangeHigh);
   ObjectSetInteger(0, "RangeHigh", OBJPROP_COLOR, clrDodgerBlue);
   ObjectSetInteger(0, "RangeHigh", OBJPROP_WIDTH, 2);

   ObjectDelete(0, "RangeLow");
   ObjectCreate(0, "RangeLow", OBJ_HLINE, 0, 0, rangeLow);
   ObjectSetInteger(0, "RangeLow", OBJPROP_COLOR, clrOrangeRed);
   ObjectSetInteger(0, "RangeLow", OBJPROP_WIDTH, 2);

   datetime startTime = StrToTime(TimeToString(TimeCurrent(), TIME_DATE) + " 14:30");
   datetime endTime = StrToTime(TimeToString(TimeCurrent(), TIME_DATE) + " 17:15");

   ObjectDelete(0, "TradingWindow");
   ObjectCreate(0, "TradingWindow", OBJ_RECTANGLE, 0, startTime, rangeHigh, endTime, rangeLow);
   ObjectSetInteger(0, "TradingWindow", OBJPROP_COLOR, clrGray);
   ObjectSetInteger(0, "TradingWindow", OBJPROP_BACK, true);
}

//+------------------------------------------------------------------+
//| Process new candle - LÓGICA CORREGIDA CON TRACKING              |
//+------------------------------------------------------------------+
void ProcessNewCandle()
{
   // Obtener vela recién cerrada
   double open1 = iOpen(Symbol(), PERIOD_M1, 1);
   double close1 = iClose(Symbol(), PERIOD_M1, 1);
   double high1 = iHigh(Symbol(), PERIOD_M1, 1);
   double low1 = iLow(Symbol(), PERIOD_M1, 1);
   datetime time1 = iTime(Symbol(), PERIOD_M1, 1);

   bool isBullish = close1 > open1;
   bool isBearish = close1 < open1;

   // PASO 1: Detectar PRIMERA vela que rompe el rango
   if(!breakoutDetected)
   {
      // Buscar ruptura alcista (compra)
      if(high1 >= rangeHigh && isBullish)
      {
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = 1;  // Alcista
         breakoutSL = low1;
         candlesAfterBreakout = 0;

         Print("===== RUPTURA ALCISTA DETECTADA =====");
         Print("Vela 1 (primera que rompe):");
         Print("  Tiempo: ", TimeToString(time1, TIME_MINUTES));
         Print("  High: ", high1, " (rompió ", rangeHigh, ")");
         Print("  Alcista: SÍ");
         Print("  SL será: ", breakoutSL);
         Print("Esperando 2 velas más...");

         // Marcar vela de ruptura en el gráfico
         MarkBreakoutCandle(time1, high1);

         if(EnableAlerts)
         {
            Alert("Ruptura ALCISTA detectada - Esperando 2 velas más");
         }

         return;
      }

      // Buscar ruptura bajista (venta)
      if(low1 <= rangeLow && isBearish)
      {
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = -1;  // Bajista
         breakoutSL = high1;
         candlesAfterBreakout = 0;

         Print("===== RUPTURA BAJISTA DETECTADA =====");
         Print("Vela 1 (primera que rompe):");
         Print("  Tiempo: ", TimeToString(time1, TIME_MINUTES));
         Print("  Low: ", low1, " (rompió ", rangeLow, ")");
         Print("  Bajista: SÍ");
         Print("  SL será: ", breakoutSL);
         Print("Esperando 2 velas más...");

         MarkBreakoutCandle(time1, low1);

         if(EnableAlerts)
         {
            Alert("Ruptura BAJISTA detectada - Esperando 2 velas más");
         }

         return;
      }
   }

   // PASO 2: Si ya hubo ruptura, contar velas
   if(breakoutDetected && !tradeExecutedToday)
   {
      candlesAfterBreakout++;

      Print("Vela ", (candlesAfterBreakout + 1), " después de ruptura:");
      Print("  Tiempo: ", TimeToString(time1, TIME_MINUTES));
      Print("  Tipo: ", (breakoutType == 1 ? "COMPRA" : "VENTA"));
      Print("  Vela es ", (isBullish ? "alcista" : (isBearish ? "bajista" : "doji")));

      // Validar que las velas sigan siendo del mismo tipo
      if(breakoutType == 1 && !isBullish)
      {
         Print("SETUP CANCELADO - Vela ", (candlesAfterBreakout + 1), " no es alcista");
         breakoutDetected = false;
         ObjectDelete(0, "BreakoutCandle");
         return;
      }

      if(breakoutType == -1 && !isBearish)
      {
         Print("SETUP CANCELADO - Vela ", (candlesAfterBreakout + 1), " no es bajista");
         breakoutDetected = false;
         ObjectDelete(0, "BreakoutCandle");
         return;
      }

      // PASO 3: Después de 2 velas adicionales, ejecutar
      if(candlesAfterBreakout == 2)
      {
         // Calcular movimiento total desde la vela de ruptura
         double breakoutHigh = iHigh(Symbol(), PERIOD_M1, 3);  // Vela que rompió
         double breakoutLow = iLow(Symbol(), PERIOD_M1, 3);
         double currentHigh = high1;  // Vela actual
         double currentLow = low1;

         double totalMove;

         if(breakoutType == 1)
         {
            totalMove = CalculatePips(currentHigh - breakoutLow);
         }
         else
         {
            totalMove = CalculatePips(breakoutHigh - currentLow);
         }

         Print("===== 3 VELAS COMPLETADAS =====");
         Print("Movimiento total: ", totalMove, " pips");

         if(totalMove <= MaxPipsMove)
         {
            if(breakoutType == 1)
            {
               ExecuteBuyOrder(breakoutSL);
            }
            else
            {
               ExecuteSellOrder(breakoutSL);
            }
         }
         else
         {
            Print("ENTRADA ANULADA - Movimiento excede ", MaxPipsMove, " pips");
            if(EnableAlerts)
            {
               Alert("Entrada anulada - Movimiento excesivo: ", totalMove, " pips");
            }
         }

         breakoutDetected = false;
         ObjectDelete(0, "BreakoutCandle");
      }
   }
