   info += "   Trade hoy: " + (tradeExecutedToday ? "✓" : "✗") + "\n";
   info += "   Intentos: " + IntegerToString(attemptNumber) + "\n\n";

   if(breakoutDetected)
   {
      info += "🎯 SETUP ACTIVO (Intento #" + IntegerToString(attemptNumber) + "):\n";
      info += "   Tipo: " + (breakoutType == 1 ? "COMPRA" : "VENTA") + "\n";
      info += "   Velas: " + IntegerToString(candlesAfterBreakout) + "/2\n";
      info += "   SL: " + DoubleToString(breakoutSL, Digits) + "\n\n";
   }

