   info += "   Balance: $" + DoubleToString(AccountBalance(), 2) + "\n";
   info += "   Equity: $" + DoubleToString(AccountEquity(), 2) + "\n\n";

   for(int i = 0; i < OrdersTotal(); i++)
   {
      if(OrderSelect(i, SELECT_BY_POS, MODE_TRADES))
      {
         if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
         {
            info += "📈 POSICIÓN:\n";
            info += "   #" + IntegerToString(OrderTicket()) + " | ";
            info += (OrderType() == OP_BUY ? "COMPRA" : "VENTA") + "\n";
            info += "   Profit: $" + DoubleToString(OrderProfit(), 2) + "\n";
            info += "   SL en BE: " + (slMovedToBE ? "✓" : "✗") + "\n";
         }
      }
   }

   Comment(info);
}
