//+------------------------------------------------------------------+
#property copyright "Trading Strategy Automation"
#property link      ""
#property version   "4.10"
#property strict

//--- Input parameters
input double RiskAmount = 100.0;          // Riesgo fijo por operación ($)
input int    MaxPipsMove = 200;           // Máximo movimiento en pips
input int    MagicNumber = 123456;        // Número mágico único
input bool   EnableAlerts = true;         // Habilitar alertas
input bool   UseNewsFilter = true;        // Filtro de noticias
input string NewsTime = "15:00";          // Hora de noticias UTC
input int    Slippage = 3;                // Slippage permitido

//--- Global variables
datetime lastTradeDate = 0;
double   rangeHigh = 0;
double   rangeLow = 0;
bool     rangeSet = false;
bool     tradingWindowActive = false;
bool     tradeExecutedToday = false;
bool     newsEventToday = false;
datetime newsEventTime = 0;
bool     slMovedToBE = false;
datetime lastCandleTime = 0;

// Variables para tracking de ruptura (PUEDEN RESETEARSE MÚLTIPLES VECES)
bool     breakoutDetected = false;
datetime breakoutCandleTime = 0;
int      breakoutType = 0;  // 1 = alcista, -1 = bajista
double   breakoutSL = 0;
int      candlesAfterBreakout = 0;
int      attemptNumber = 0;  // Contador de intentos

//+------------------------------------------------------------------+
//| Expert initialization function                                   |
//+------------------------------------------------------------------+
int OnInit()
{
   Print("==================================================");
   Print("US30 Range Breakout - MULTI-ATTEMPT VERSION - UTC");
   Print("==================================================");
   Print("HORARIOS EN UTC (GMT+0)");
   Print("Rango: 9:00 - 14:00 UTC");
   Print("Trading: 14:30 - 17:15 UTC");
   Print("Permite múltiples intentos de ruptura");
   Print("Riesgo fijo: $", RiskAmount);
   Print("==================================================");

   if(Period() != PERIOD_M1)
   {
      Alert("ADVERTENCIA: Este EA debe ejecutarse en M1");
   }

   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| Expert deinitialization function                                 |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   ObjectDelete(0, "RangeHigh");
   ObjectDelete(0, "RangeLow");
   ObjectDelete(0, "TradingWindow");
   ObjectDelete(0, "BreakoutCandle");
   Comment("");
}

//+------------------------------------------------------------------+
//| Expert tick function                                             |
//+------------------------------------------------------------------+
void OnTick()
{
   // Verificar nuevo día
   if(TimeDayOfYear(TimeCurrent()) != TimeDayOfYear(lastTradeDate))
   {
      ResetDaily();
   }

   datetime currentTime = TimeCurrent();
   int currentHour = TimeHour(currentTime);
   int currentMinute = TimeMinute(currentTime);

   // PASO #1: Establecer rango 9:00 - 14:00 UTC
   if(currentHour >= 9 && currentHour < 14)
   {
      UpdateRange();
   }

   // Finalizar rango a las 14:00 UTC
   if(currentHour == 14 && currentMinute == 0 && !rangeSet)
   {
      FinalizeRange();
   }

   // PASO #2: Ventana de trading 14:30 - 17:15 UTC
   tradingWindowActive = false;
   if((currentHour == 14 && currentMinute >= 30) || 
      (currentHour > 14 && currentHour < 17) ||
      (currentHour == 17 && currentMinute <= 15))
   {
      tradingWindowActive = true;

      if(UseNewsFilter && newsEventToday && currentTime < newsEventTime)
      {
         tradingWindowActive = false;
         return;
      }
   }

   // Verificar nueva vela
   datetime currentCandleTime = iTime(Symbol(), PERIOD_M1, 0);
   if(currentCandleTime != lastCandleTime)
   {
      lastCandleTime = currentCandleTime;

      // PASO #3: Lógica de entrada - permite múltiples intentos
      if(tradingWindowActive && rangeSet && !tradeExecutedToday)
      {
         ProcessNewCandle();
      }
   }

   // PASO #4: Gestión de trades
   ManageOpenTrades();

   UpdateDisplay();
}

//+------------------------------------------------------------------+
//| Reset daily variables                                            |
//+------------------------------------------------------------------+
void ResetDaily()
{
   Print("===== NUEVO DÍA =====");
   Print("Fecha: ", TimeToString(TimeCurrent(), TIME_DATE));

   lastTradeDate = TimeCurrent();
   rangeHigh = 0;
   rangeLow = 999999;
   rangeSet = false;
   tradingWindowActive = false;
   tradeExecutedToday = false;
   slMovedToBE = false;

   // Reset tracking variables
   breakoutDetected = false;
   breakoutCandleTime = 0;
   breakoutType = 0;
   breakoutSL = 0;
   candlesAfterBreakout = 0;
   attemptNumber = 0;

   ObjectDelete(0, "RangeHigh");
   ObjectDelete(0, "RangeLow");
   ObjectDelete(0, "TradingWindow");
   ObjectDelete(0, "BreakoutCandle");

   CheckNewsToday();
}

//+------------------------------------------------------------------+
//| Update range                                                     |
//+------------------------------------------------------------------+
void UpdateRange()
{
   for(int i = 1; i < 300; i++)
   {
      datetime barTime = iTime(Symbol(), PERIOD_M1, i);
      int barHour = TimeHour(barTime);

      if(barHour >= 9 && barHour < 14)
      {
         double high = iHigh(Symbol(), PERIOD_M1, i);
         double low = iLow(Symbol(), PERIOD_M1, i);

         if(high > rangeHigh) rangeHigh = high;
         if(low < rangeLow) rangeLow = low;
      }
   }
}

//+------------------------------------------------------------------+
//| Finalize range                                                   |
//+------------------------------------------------------------------+
void FinalizeRange()
{
   if(rangeHigh > 0 && rangeLow < 999999)
   {
      rangeSet = true;
      Print("===== RANGO ESTABLECIDO =====");
      Print("Range High: ", rangeHigh);
      Print("Range Low: ", rangeLow);
      Print("Range Size: ", CalculatePips(rangeHigh - rangeLow), " pips");

      DrawRangeLines();

      if(EnableAlerts)
      {
         Alert("Rango establecido - High: ", rangeHigh, " Low: ", rangeLow);
      }
   }
}

//+------------------------------------------------------------------+
//| Draw range lines                                                 |
//+------------------------------------------------------------------+
void DrawRangeLines()
{
   ObjectDelete(0, "RangeHigh");
   ObjectCreate(0, "RangeHigh", OBJ_HLINE, 0, 0, rangeHigh);
   ObjectSetInteger(0, "RangeHigh", OBJPROP_COLOR, clrDodgerBlue);
   ObjectSetInteger(0, "RangeHigh", OBJPROP_WIDTH, 2);

   ObjectDelete(0, "RangeLow");
   ObjectCreate(0, "RangeLow", OBJ_HLINE, 0, 0, rangeLow);
   ObjectSetInteger(0, "RangeLow", OBJPROP_COLOR, clrOrangeRed);
   ObjectSetInteger(0, "RangeLow", OBJPROP_WIDTH, 2);

   datetime startTime = StrToTime(TimeToString(TimeCurrent(), TIME_DATE) + " 14:30");
   datetime endTime = StrToTime(TimeToString(TimeCurrent(), TIME_DATE) + " 17:15");

   ObjectDelete(0, "TradingWindow");
   ObjectCreate(0, "TradingWindow", OBJ_RECTANGLE, 0, startTime, rangeHigh, endTime, rangeLow);
   ObjectSetInteger(0, "TradingWindow", OBJPROP_COLOR, clrGray);
   ObjectSetInteger(0, "TradingWindow", OBJPROP_BACK, true);
}

//+------------------------------------------------------------------+
//| Process new candle - PERMITE MÚLTIPLES INTENTOS                 |
//+------------------------------------------------------------------+
void ProcessNewCandle()
{
   // Obtener vela recién cerrada
   double open1 = iOpen(Symbol(), PERIOD_M1, 1);
   double close1 = iClose(Symbol(), PERIOD_M1, 1);
   double high1 = iHigh(Symbol(), PERIOD_M1, 1);
   double low1 = iLow(Symbol(), PERIOD_M1, 1);
   datetime time1 = iTime(Symbol(), PERIOD_M1, 1);

   bool isBullish = close1 > open1;
   bool isBearish = close1 < open1;

   // PASO 1: Detectar PRIMERA vela que rompe (si no hay ruptura activa)
   if(!breakoutDetected)
   {
      // Buscar ruptura alcista (compra)
      if(high1 >= rangeHigh && isBullish)
      {
         attemptNumber++;
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = 1;  // Alcista
         breakoutSL = low1;
         candlesAfterBreakout = 0;

         Print("===== INTENTO #", attemptNumber, " - RUPTURA ALCISTA =====");
         Print("Vela que rompe:");
         Print("  Tiempo: ", TimeToString(time1, TIME_MINUTES), " UTC");
         Print("  High: ", high1, " (rompió ", rangeHigh, ")");
         Print("  Alcista: SÍ");
         Print("  SL será: ", breakoutSL);
         Print("Esperando 2 velas alcistas más...");

         MarkBreakoutCandle(time1, high1);

         if(EnableAlerts)
         {
            Alert("Intento #", attemptNumber, " - Ruptura ALCISTA detectada");
         }

         return;
      }

      // Buscar ruptura bajista (venta)
      if(low1 <= rangeLow && isBearish)
      {
         attemptNumber++;
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = -1;  // Bajista
         breakoutSL = high1;
         candlesAfterBreakout = 0;

         Print("===== INTENTO #", attemptNumber, " - RUPTURA BAJISTA =====");
         Print("Vela que rompe:");
         Print("  Tiempo: ", TimeToString(time1, TIME_MINUTES), " UTC");
         Print("  Low: ", low1, " (rompió ", rangeLow, ")");
         Print("  Bajista: SÍ");
         Print("  SL será: ", breakoutSL);
         Print("Esperando 2 velas bajistas más...");

         MarkBreakoutCandle(time1, low1);

         if(EnableAlerts)
         {
            Alert("Intento #", attemptNumber, " - Ruptura BAJISTA detectada");
         }

         return;
      }
   }

   // PASO 2: Si ya hubo ruptura, contar velas
   if(breakoutDetected && !tradeExecutedToday)
   {
      candlesAfterBreakout++;

      Print("Vela ", (candlesAfterBreakout + 1), " del setup (Intento #", attemptNumber, "):");
      Print("  Tiempo: ", TimeToString(time1, TIME_MINUTES), " UTC");
      Print("  Tipo esperado: ", (breakoutType == 1 ? "ALCISTA" : "BAJISTA"));
      Print("  Vela es: ", (isBullish ? "alcista" : (isBearish ? "bajista" : "doji")));

      // Validar que las velas sigan siendo del mismo tipo
      if(breakoutType == 1 && !isBullish)
      {
         Print("╔════════════════════════════════════════╗");
         Print("║ INTENTO #", attemptNumber, " CANCELADO              ║");
         Print("║ Vela ", (candlesAfterBreakout + 1), " NO es alcista          ║");
         Print("║ BUSCANDO NUEVA RUPTURA...              ║");
         Print("╚════════════════════════════════════════╝");

         // RESETEAR para permitir nuevo intento
         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");

         if(EnableAlerts)
         {
            Alert("Intento #", attemptNumber, " cancelado - Buscando nueva ruptura");
         }

         return;
      }

      if(breakoutType == -1 && !isBearish)
      {
         Print("╔════════════════════════════════════════╗");
         Print("║ INTENTO #", attemptNumber, " CANCELADO              ║");
         Print("║ Vela ", (candlesAfterBreakout + 1), " NO es bajista          ║");
         Print("║ BUSCANDO NUEVA RUPTURA...              ║");
         Print("╚════════════════════════════════════════╝");

         // RESETEAR para permitir nuevo intento
         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");

         if(EnableAlerts)
         {
            Alert("Intento #", attemptNumber, " cancelado - Buscando nueva ruptura");
         }

         return;
      }

      Print("✓ Vela válida - Contador: ", candlesAfterBreakout, "/2");

      // PASO 3: Después de 2 velas adicionales válidas, ejecutar
      if(candlesAfterBreakout == 2)
      {
         // Calcular movimiento total desde la vela de ruptura
         double breakoutHigh = iHigh(Symbol(), PERIOD_M1, 3);  // Vela que rompió
         double breakoutLow = iLow(Symbol(), PERIOD_M1, 3);
         double currentHigh = high1;  // Vela actual
         double currentLow = low1;

         double totalMove;

         if(breakoutType == 1)
         {
            totalMove = CalculatePips(currentHigh - breakoutLow);
         }
         else
         {
            totalMove = CalculatePips(breakoutHigh - currentLow);
         }

         Print("╔════════════════════════════════════════╗");
         Print("║ INTENTO #", attemptNumber, " COMPLETADO            ║");
         Print("║ 3 VELAS CONSECUTIVAS VÁLIDAS          ║");
         Print("╚════════════════════════════════════════╝");
         Print("Movimiento total: ", totalMove, " pips");

         if(totalMove <= MaxPipsMove)
         {
            if(breakoutType == 1)
            {
               ExecuteBuyOrder(breakoutSL);
            }
            else
            {
               ExecuteSellOrder(breakoutSL);
            }
         }
         else
         {
            Print("ENTRADA ANULADA - Movimiento excede ", MaxPipsMove, " pips");
            if(EnableAlerts)
            {
               Alert("Entrada anulada - Movimiento excesivo: ", totalMove, " pips");
            }
         }

         breakoutDetected = false;
         ObjectDelete(0, "BreakoutCandle");
      }
   }
}

//+------------------------------------------------------------------+
//| Mark breakout candle on chart                                    |
//+------------------------------------------------------------------+
void MarkBreakoutCandle(datetime time, double price)
{
   ObjectDelete(0, "BreakoutCandle");
   ObjectCreate(0, "BreakoutCandle", OBJ_ARROW, 0, time, price);
   ObjectSetInteger(0, "BreakoutCandle", OBJPROP_COLOR, clrYellow);
   ObjectSetInteger(0, "BreakoutCandle", OBJPROP_ARROWCODE, 108);
   ObjectSetInteger(0, "BreakoutCandle", OBJPROP_WIDTH, 3);
}

//+------------------------------------------------------------------+
//| Calculate pips                                                   |
//+------------------------------------------------------------------+
double CalculatePips(double priceDistance)
{
   double pips = priceDistance / Point;

   if(StringFind(Symbol(), "US30") >= 0 || StringFind(Symbol(), "DOW") >= 0)
   {
      pips = pips / 10.0;
   }

   return pips;
}

//+------------------------------------------------------------------+
//| Execute Buy Order                                                |
//+------------------------------------------------------------------+
void ExecuteBuyOrder(double sl)
{
   double entryPrice = Ask;
   double tp = entryPrice + (entryPrice - sl);

   double lotSize = CalculateLotSize(sl, OP_BUY);

   if(lotSize > 0)
   {
      int ticket = OrderSend(Symbol(), OP_BUY, lotSize, Ask, Slippage, sl, tp, 
                            "US30_MultiAttempt", MagicNumber, 0, clrGreen);

      if(ticket > 0)
      {
         tradeExecutedToday = true;
         slMovedToBE = false;

         Print("╔════════════════════════════════════════╗");
         Print("║         COMPRA EJECUTADA               ║");
         Print("╚════════════════════════════════════════╝");
         Print("Intento exitoso: #", attemptNumber);
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
         Print("Entry: ", Ask, " | SL: ", sl, " | TP: ", tp);
         Print("Riesgo: $", RiskAmount);
         Print("UTC: ", TimeToString(TimeCurrent(), TIME_MINUTES));

         if(EnableAlerts)
         {
            Alert("COMPRA ejecutada (Intento #", attemptNumber, ") - Ticket: ", ticket);
         }
      }
      else
      {
         Print("ERROR: ", GetLastError());
      }
   }
}

//+------------------------------------------------------------------+
//| Execute Sell Order                                               |
//+------------------------------------------------------------------+
void ExecuteSellOrder(double sl)
{
   double entryPrice = Bid;
   double tp = entryPrice - (sl - entryPrice);

   double lotSize = CalculateLotSize(sl, OP_SELL);

   if(lotSize > 0)
   {
      int ticket = OrderSend(Symbol(), OP_SELL, lotSize, Bid, Slippage, sl, tp, 
                            "US30_MultiAttempt", MagicNumber, 0, clrRed);

      if(ticket > 0)
      {
         tradeExecutedToday = true;
         slMovedToBE = false;

         Print("╔════════════════════════════════════════╗");
         Print("║         VENTA EJECUTADA                ║");
         Print("╚════════════════════════════════════════╝");
         Print("Intento exitoso: #", attemptNumber);
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
         Print("Entry: ", Bid, " | SL: ", sl, " | TP: ", tp);
         Print("Riesgo: $", RiskAmount);
         Print("UTC: ", TimeToString(TimeCurrent(), TIME_MINUTES));

         if(EnableAlerts)
         {
            Alert("VENTA ejecutada (Intento #", attemptNumber, ") - Ticket: ", ticket);
         }
      }
      else
      {
         Print("ERROR: ", GetLastError());
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate Lot Size                                               |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice, int orderType)
{
   double slDistance;

   if(orderType == OP_BUY)
      slDistance = Ask - slPrice;
   else
      slDistance = slPrice - Bid;

   if(slDistance <= 0)
   {
      Print("ERROR: SL distance inválida");
      return 0;
   }

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);

   if(tickValue == 0 || tickSize == 0)
   {
      Print("ERROR: Tick value/size inválidos");
      return 0;
   }

   double lotSize = (RiskAmount / (slDistance / tickSize * tickValue));

   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = NormalizeDouble(lotSize, 2);
   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   return lotSize;
}

//+------------------------------------------------------------------+
//| Manage open trades                                               |
//+------------------------------------------------------------------+
void ManageOpenTrades()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;

      if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
      {
         double openPrice = OrderOpenPrice();
         double sl = OrderStopLoss();
         double tp = OrderTakeProfit();

         if(OrderType() == OP_BUY)
         {
            double distance = tp - openPrice;
            double eightyPercent = openPrice + (distance * 0.8);

            if(Bid >= eightyPercent && sl < openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("SL movido a BE - Ticket: ", OrderTicket());

                  if(EnableAlerts)
                  {
                     Alert("SL en BE - Ticket: ", OrderTicket());
                  }
               }
            }
         }
         else if(OrderType() == OP_SELL)
         {
            double distance = openPrice - tp;
            double eightyPercent = openPrice - (distance * 0.8);

            if(Ask <= eightyPercent && sl > openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("SL movido a BE - Ticket: ", OrderTicket());

                  if(EnableAlerts)
                  {
                     Alert("SL en BE - Ticket: ", OrderTicket());
                  }
               }
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| Check news                                                       |
//+------------------------------------------------------------------+
void CheckNewsToday()
{
   if(!UseNewsFilter)
   {
      newsEventToday = false;
      return;
   }

   string todayDate = TimeToString(TimeCurrent(), TIME_DATE);
   newsEventTime = StrToTime(todayDate + " " + NewsTime);
   newsEventToday = true;
}

//+------------------------------------------------------------------+
//| Update display                                                   |
//+------------------------------------------------------------------+
void UpdateDisplay()
{
   string info = "\n╔════════════════════════════════════════╗\n";
   info += "║  US30 - MULTI-ATTEMPT UTC VERSION     ║\n";
   info += "╚════════════════════════════════════════╝\n\n";

   info += "🌍 UTC: " + TimeToString(TimeCurrent(), TIME_MINUTES) + "\n";
   info += "💰 Riesgo: $" + DoubleToString(RiskAmount, 2) + "\n\n";

   info += "📊 RANGO:\n";
   info += "   High: " + DoubleToString(rangeHigh, Digits) + "\n";
   info += "   Low: " + DoubleToString(rangeLow, Digits) + "\n";
   info += "   Estado: " + (rangeSet ? "✓" : "✗") + "\n\n";

   info += "⏰ TRADING:\n";
   info += "   Ventana: " + (tradingWindowActive ? "✓ ACTIVA" : "✗ Cerrada") + "\n";
   info += "   Trade hoy: " + (tradeExecutedToday ? "✓" : "✗") + "\n";
   info += "   Intentos: " + IntegerToString(attemptNumber) + "\n\n";

   if(breakoutDetected)
   {
      info += "🎯 SETUP ACTIVO (Intento #" + IntegerToString(attemptNumber) + "):\n";
      info += "   Tipo: " + (breakoutType == 1 ? "COMPRA" : "VENTA") + "\n";
      info += "   Velas: " + IntegerToString(candlesAfterBreakout) + "/2\n";
      info += "   SL: " + DoubleToString(breakoutSL, Digits) + "\n\n";
   }

   info += "💼 CUENTA:\n";
   info += "   Balance: $" + DoubleToString(AccountBalance(), 2) + "\n";
   info += "   Equity: $" + DoubleToString(AccountEquity(), 2) + "\n\n";

   for(int i = 0; i < OrdersTotal(); i++)
   {
      if(OrderSelect(i, SELECT_BY_POS, MODE_TRADES))
      {
         if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
         {
            info += "📈 POSICIÓN:\n";
            info += "   #" + IntegerToString(OrderTicket()) + " | ";
            info += (OrderType() == OP_BUY ? "COMPRA" : "VENTA") + "\n";
            info += "   Profit: $" + DoubleToString(OrderProfit(), 2) + "\n";
            info += "   SL en BE: " + (slMovedToBE ? "✓" : "✗") + "\n";
         }
      }
   }

   Comment(info);
}
