//+------------------------------------------------------------------+
//| Process new candle - VALIDACIÓN ESTRICTA DE RUPTURA             |
//+------------------------------------------------------------------+
void ProcessNewCandle()
{
   double open1 = iOpen(Symbol(), PERIOD_M1, 1);
   double close1 = iClose(Symbol(), PERIOD_M1, 1);
   double high1 = iHigh(Symbol(), PERIOD_M1, 1);
   double low1 = iLow(Symbol(), PERIOD_M1, 1);
   datetime time1 = iTime(Symbol(), PERIOD_M1, 1);

   bool isBullish = close1 > open1;
   bool isBearish = close1 < open1;

   // PASO 1: Detectar primera vela que ROMPE el rango
   if(!breakoutDetected)
   {
      // VALIDACIÓN CRÍTICA: La vela debe CERRAR FUERA del rango
      // Para compra: El CIERRE debe estar por ENCIMA del rangeHigh
      if(close1 > rangeHigh && isBullish)
      {
         attemptNumber++;
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = 1;
         breakoutSL = low1;
         candlesAfterBreakout = 0;

         Print("===== INTENTO #", attemptNumber, " - RUPTURA ALCISTA =====");
         Print("VALIDACIÓN PASADA:");
         Print("  ✓ Close: ", close1, " > rangeHigh: ", rangeHigh);
         Print("  ✓ Vela alcista");
         Print("  ✓ High: ", high1);
         Print("  ✓ Low (SL): ", low1);
         Print("Esperando 2 velas alcistas más...");

         MarkBreakoutCandle(time1, high1);

         if(EnableAlerts)
         {
            Alert("Intento #", attemptNumber, " - Ruptura ALCISTA válida");
         }

         return;
      }

      // Para venta: El CIERRE debe estar por DEBAJO del rangeLow
      if(close1 < rangeLow && isBearish)
      {
         attemptNumber++;
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = -1;
         breakoutSL = high1;
         candlesAfterBreakout = 0;

         Print("===== INTENTO #", attemptNumber, " - RUPTURA BAJISTA =====");
         Print("VALIDACIÓN PASADA:");
         Print("  ✓ Close: ", close1, " < rangeLow: ", rangeLow);
         Print("  ✓ Vela bajista");
         Print("  ✓ Low: ", low1);
         Print("  ✓ High (SL): ", high1);
         Print("Esperando 2 velas bajistas más...");

         MarkBreakoutCandle(time1, low1);

         if(EnableAlerts)
         {
            Alert("Intento #", attemptNumber, " - Ruptura BAJISTA válida");
         }

         return;
      }

      // LOGS DE DEBUG: Mostrar por qué NO es ruptura
      if(high1 >= rangeHigh && !isBullish)
      {
         Print("DEBUG: High tocó rango pero vela NO es alcista (Close: ", close1, " <= Open: ", open1, ")");
      }
      if(high1 >= rangeHigh && isBullish && close1 <= rangeHigh)
      {
         Print("DEBUG: Vela alcista pero Close NO está fuera del rango (Close: ", close1, " <= rangeHigh: ", rangeHigh, ")");
      }
      if(low1 <= rangeLow && !isBearish)
      {
         Print("DEBUG: Low tocó rango pero vela NO es bajista (Close: ", close1, " >= Open: ", open1, ")");
      }
      if(low1 <= rangeLow && isBearish && close1 >= rangeLow)
      {
         Print("DEBUG: Vela bajista pero Close NO está fuera del rango (Close: ", close1, " >= rangeLow: ", rangeLow, ")");
      }
   }

   // PASO 2: Contar velas después de ruptura
   if(breakoutDetected && !tradeExecutedToday)
   {
      candlesAfterBreakout++;

      Print("Vela ", (candlesAfterBreakout + 1), " del setup (Intento #", attemptNumber, "):");
      Print("  Close: ", close1, " | Open: ", open1);
      Print("  Tipo esperado: ", (breakoutType == 1 ? "ALCISTA" : "BAJISTA"));
      Print("  Vela es: ", (isBullish ? "alcista" : (isBearish ? "bajista" : "doji")));

      // Validar tipo de vela
      if(breakoutType == 1 && !isBullish)
      {
         Print("╔════════════════════════════════════════╗");
         Print("║ INTENTO #", attemptNumber, " CANCELADO              ║");
         Print("║ Vela NO es alcista                    ║");
         Print("╚════════════════════════════════════════╝");

         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");
         return;
      }

      if(breakoutType == -1 && !isBearish)
      {
         Print("╔════════════════════════════════════════╗");
         Print("║ INTENTO #", attemptNumber, " CANCELADO              ║");
         Print("║ Vela NO es bajista                    ║");
         Print("╚════════════════════════════════════════╝");

         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");
         return;
      }

      Print("✓ Vela válida - Contador: ", candlesAfterBreakout, "/2");

      // PASO 3: Ejecutar después de 2 velas válidas
      if(candlesAfterBreakout == 2)
      {
         double breakoutHigh = iHigh(Symbol(), PERIOD_M1, 3);
         double breakoutLow = iLow(Symbol(), PERIOD_M1, 3);
         double currentHigh = high1;
         double currentLow = low1;

         double totalMove;

         if(breakoutType == 1)
         {
            totalMove = CalculatePips(currentHigh - breakoutLow);
         }
         else
         {
            totalMove = CalculatePips(breakoutHigh - currentLow);
         }

         Print("╔════════════════════════════════════════╗");
         Print("║ INTENTO #", attemptNumber, " COMPLETADO            ║");
         Print("╚════════════════════════════════════════╝");
         Print("Movimiento: ", totalMove, " pips");

         if(totalMove <= MaxPipsMove)
         {
            if(breakoutType == 1)
            {
               ExecuteBuyOrder(breakoutSL);
            }
            else
            {
               ExecuteSellOrder(breakoutSL);
            }
         }
         else
         {
            Print("ANULADO - Movimiento excede ", MaxPipsMove, " pips");
         }

         breakoutDetected = false;
         ObjectDelete(0, "BreakoutCandle");
      }
   }
}

