         tradeExecutedToday = true;
         slMovedToBE = false;

         Print("");
         Print("╔════════════════════════════════════════╗");
         Print("║       COMPRA EJECUTADA ✓               ║");
         Print("╚════════════════════════════════════════╝");
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
