      else
      {
         Print("ERROR al abrir COMPRA: ", GetLastError());
      }
   }
}

//+------------------------------------------------------------------+
//| Execute Sell Order                                               |
//+------------------------------------------------------------------+
void ExecuteSellOrder(double sl, double tp)
{
   double lotSize = CalculateLotSize(sl, OP_SELL);

   if(lotSize > 0)
   {
      int ticket = OrderSend(Symbol(), OP_SELL, lotSize, Bid, Slippage, sl, tp, 
                            "US30_Correct", MagicNumber, 0, clrRed);

      if(ticket > 0)
      {
         tradeExecutedToday = true;
         slMovedToBE = false;

         Print("");
         Print("╔════════════════════════════════════════╗");
         Print("║       VENTA EJECUTADA ✓                ║");
         Print("╚════════════════════════════════════════╝");
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
         Print("Entry: ", Bid);
         Print("SL: ", sl);
         Print("TP: ", tp);
         Print("Riesgo: $", RiskAmount);
         Print("UTC: ", TimeToString(TimeCurrent(), TIME_MINUTES));

         if(EnableAlerts)
         {
            Alert("VENTA ejecutada - Ticket: ", ticket);
         }
      }
      else
      {
         Print("ERROR al abrir VENTA: ", GetLastError());
      }
   }
}

//+------------------------------------------------------------------+
//| Calculate Lot Size                                               |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice, int orderType)
{
   double slDistance;

   if(orderType == OP_BUY)
      slDistance = Ask - slPrice;
   else
      slDistance = slPrice - Bid;

   if(slDistance <= 0)
   {
      Print("ERROR: SL distance inválida");
      return 0;
   }

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);

   if(tickValue == 0 || tickSize == 0)
   {
      Print("ERROR: Tick value/size inválidos");
      return 0;
   }

   double lotSize = (RiskAmount / (slDistance / tickSize * tickValue));

   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = NormalizeDouble(lotSize, 2);
   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   return lotSize;
}

//+------------------------------------------------------------------+
//| Manage open trades                                               |
//+------------------------------------------------------------------+
void ManageOpenTrades()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;

      if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
      {
         double openPrice = OrderOpenPrice();
         double sl = OrderStopLoss();
         double tp = OrderTakeProfit();

         if(OrderType() == OP_BUY)
         {
            double distance = tp - openPrice;
            double eightyPercent = openPrice + (distance * 0.8);

            if(Bid >= eightyPercent && sl < openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("SL movido a BE - Ticket: ", OrderTicket());

                  if(EnableAlerts)
                  {
                     Alert("SL en BE - Ticket: ", OrderTicket());
                  }
               }
            }
         }
         else if(OrderType() == OP_SELL)
         {
            double distance = openPrice - tp;
            double eightyPercent = openPrice - (distance * 0.8);

            if(Ask <= eightyPercent && sl > openPrice && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, openPrice, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("SL movido a BE - Ticket: ", OrderTicket());

                  if(EnableAlerts)
                  {
                     Alert("SL en BE - Ticket: ", OrderTicket());
                  }
               }
            }
         }
      }
   }
}

