//+------------------------------------------------------------------+
//| Update range                                                     |
//+------------------------------------------------------------------+
void UpdateRange()
{
   for(int i = 1; i < 300; i++)
   {
      datetime barTime = iTime(Symbol(), PERIOD_M1, i);
      int barHour = TimeHour(barTime);

      if(barHour >= 9 && barHour < 14)
      {
         double high = iHigh(Symbol(), PERIOD_M1, i);
         double low = iLow(Symbol(), PERIOD_M1, i);

         if(high > rangeHigh) rangeHigh = high;
         if(low < rangeLow) rangeLow = low;
      }
   }
}

//+------------------------------------------------------------------+
//| Finalize range                                                   |
//+------------------------------------------------------------------+
void FinalizeRange()
{
   if(rangeHigh > 0 && rangeLow < 999999)
   {
      rangeSet = true;
      Print("╔══════════════════════════════════════════════════╗");
      Print("║            RANGO ESTABLECIDO                     ║");
      Print("╚══════════════════════════════════════════════════╝");
      Print("Range High: ", rangeHigh);
      Print("Range Low: ", rangeLow);
      Print("Range Size: ", CalculatePips(rangeHigh - rangeLow), " pips");
      Print("Hora UTC: ", TimeToString(TimeCurrent(), TIME_MINUTES));

      DrawRangeLines();

      if(EnableAlerts)
      {
         Alert("✅ Rango establecido - High: ", rangeHigh, " Low: ", rangeLow);
      }
   }
}

