   info += "   Margen libre: $" + DoubleToString(AccountFreeMargin(), 2) + "\n";
   info += "   Margen usado: $" + DoubleToString(AccountMargin(), 2) + "\n";
   info += "   Profit/Loss: $" + DoubleToString(AccountProfit(), 2) + "\n\n";

   // POSICIONES ABIERTAS
   int openPositions = 0;
   for(int i = 0; i < OrdersTotal(); i++)
   {
      if(OrderSelect(i, SELECT_BY_POS, MODE_TRADES))
      {
         if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
         {
            openPositions++;

            double currentPrice = (OrderType() == OP_BUY) ? Bid : Ask;
            double pipsProfit = 0;

            if(OrderType() == OP_BUY)
               pipsProfit = CalculatePips(Bid - OrderOpenPrice());
            else
               pipsProfit = CalculatePips(OrderOpenPrice() - Ask);

            double percentToTP = 0;
            if(OrderType() == OP_BUY)
               percentToTP = ((Bid - OrderOpenPrice()) / (OrderTakeProfit() - OrderOpenPrice())) * 100;
            else
               percentToTP = ((OrderOpenPrice() - Ask) / (OrderOpenPrice() - OrderTakeProfit())) * 100;

            info += "📈 POSICIÓN ABIERTA:\n";
            info += "   Ticket: #" + IntegerToString(OrderTicket()) + "\n";
            info += "   Tipo: " + (OrderType() == OP_BUY ? "COMPRA ⬆️" : "VENTA ⬇️") + "\n";
            info += "   Lotes: " + DoubleToString(OrderLots(), 2) + "\n";
            info += "   Precio entrada: " + DoubleToString(OrderOpenPrice(), Digits) + "\n";
            info += "   Precio actual: " + DoubleToString(currentPrice, Digits) + "\n";
            info += "   Stop Loss: " + DoubleToString(OrderStopLoss(), Digits) + "\n";
            info += "   Take Profit: " + DoubleToString(OrderTakeProfit(), Digits) + "\n";
            info += "   Progreso: " + DoubleToString(percentToTP, 1) + "% del TP\n";
            info += "   Pips P/L: " + DoubleToString(pipsProfit, 1) + " pips\n";
            info += "   Profit: $" + DoubleToString(OrderProfit(), 2) + "\n";
            info += "   SL en BE: " + (slMovedToBE ? "✓ SÍ (+" + DoubleToString(BEProfitPercent, 0) + "%)" : "✗ NO") + "\n";
            info += "   Hora apertura: " + TimeToString(OrderOpenTime(), TIME_MINUTES) + "\n";
         }
      }
   }

   if(openPositions == 0)
   {
      info += "📊 No hay posiciones abiertas\n";
   }

   info += "\n╚═══════════════════════════════════════════════════════════╝";

   Comment(info);
}
