//+------------------------------------------------------------------+
//|                  US30_Range_Breakout_FINAL_V1_DEBUG.mq4         |
//|                  VERSIÓN CON DEBUGGING EXTENSIVO                 |
//+------------------------------------------------------------------+
#property copyright "Trading Strategy Automation"
#property link      ""
#property version   "1.01"
#property strict

//--- Input parameters
input double RiskAmount = 100.0;
input int    MaxPipsMove = 200;
input double BEPercent = 80.0;
input double BEProfitPercent = 10.0;
input int    MagicNumber = 123456;
input bool   EnableAlerts = true;
input bool   UseNewsFilter = true;
input string NewsTime = "15:00";
input int    Slippage = 3;

//--- Global variables
datetime lastTradeDate = 0;
double   rangeHigh = 0;
double   rangeLow = 0;
bool     rangeSet = false;
bool     tradingWindowActive = false;
bool     tradeExecutedToday = false;
bool     newsEventToday = false;
datetime newsEventTime = 0;
bool     slMovedToBE = false;
datetime lastCandleTime = 0;

bool     breakoutDetected = false;
datetime breakoutCandleTime = 0;
int      breakoutType = 0;
double   breakoutSL = 0;
int      candlesAfterBreakout = 0;
int      attemptNumber = 0;

datetime rangeStartTime = 0;
datetime rangeEndTime = 0;
datetime tradingStartTime = 0;
datetime tradingEndTime = 0;

//+------------------------------------------------------------------+
int OnInit()
{
   Print("╔══════════════════════════════════════════════════╗");
   Print("║  US30 RANGE BREAKOUT - DEBUG VERSION 1.01       ║");
   Print("╚══════════════════════════════════════════════════╝");

   if(Period() != PERIOD_M1)
   {
      Alert("⚠️ ADVERTENCIA: Este EA debe ejecutarse en M1");
   }

   // Test de broker
   Print("=== TEST DE BROKER ===");
   Print("Symbol: ", Symbol());
   Print("Digits: ", Digits);
   Print("Point: ", Point);
   Print("Tick Value: ", MarketInfo(Symbol(), MODE_TICKVALUE));
   Print("Tick Size: ", MarketInfo(Symbol(), MODE_TICKSIZE));
   Print("Min Lot: ", MarketInfo(Symbol(), MODE_MINLOT));
   Print("Max Lot: ", MarketInfo(Symbol(), MODE_MAXLOT));
   Print("Lot Step: ", MarketInfo(Symbol(), MODE_LOTSTEP));
   Print("Spread: ", MarketInfo(Symbol(), MODE_SPREAD));
   Print("Stop Level: ", MarketInfo(Symbol(), MODE_STOPLEVEL));
   Print("Account Balance: $", AccountBalance());
   Print("Account Leverage: 1:", AccountLeverage());

   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   ObjectDelete(0, "RangeHigh");
   ObjectDelete(0, "RangeLow");
   ObjectDelete(0, "TradingWindow");
   ObjectDelete(0, "BreakoutCandle");
   Comment("");
}

//+------------------------------------------------------------------+
void OnTick()
{
   if(TimeDayOfYear(TimeCurrent()) != TimeDayOfYear(lastTradeDate))
   {
      ResetDaily();
   }

   datetime currentTime = TimeCurrent();
   int currentHour = TimeHour(currentTime);
   int currentMinute = TimeMinute(currentTime);

   if(currentHour >= 9 && currentHour < 14)
   {
      UpdateRange();
   }

   if(currentHour == 14 && currentMinute == 0 && !rangeSet)
   {
      FinalizeRange();
   }

   tradingWindowActive = false;
   if((currentHour == 14 && currentMinute >= 30) || 
      (currentHour > 14 && currentHour < 17) ||
      (currentHour == 17 && currentMinute <= 15))
   {
      tradingWindowActive = true;

      if(UseNewsFilter && newsEventToday && currentTime < newsEventTime)
      {
         tradingWindowActive = false;
         return;
      }
   }

   datetime currentCandleTime = iTime(Symbol(), PERIOD_M1, 0);
   if(currentCandleTime != lastCandleTime)
   {
      lastCandleTime = currentCandleTime;

      if(tradingWindowActive && rangeSet && !tradeExecutedToday)
      {
         ProcessNewCandle();
      }
   }

   ManageOpenTrades();
   UpdateDisplay();
}

//+------------------------------------------------------------------+
void ResetDaily()
{
   Print("╔══════════════════════════════════════════════════╗");
   Print("║              NUEVO DÍA DE TRADING                ║");
   Print("╚══════════════════════════════════════════════════╝");

   lastTradeDate = TimeCurrent();
   rangeHigh = 0;
   rangeLow = 999999;
   rangeSet = false;
   tradingWindowActive = false;
   tradeExecutedToday = false;
   slMovedToBE = false;

   breakoutDetected = false;
   breakoutCandleTime = 0;
   breakoutType = 0;
   breakoutSL = 0;
   candlesAfterBreakout = 0;
   attemptNumber = 0;

   string todayDate = TimeToString(TimeCurrent(), TIME_DATE);
   rangeStartTime = StrToTime(todayDate + " 09:00");
   rangeEndTime = StrToTime(todayDate + " 14:00");
   tradingStartTime = StrToTime(todayDate + " 14:30");
   tradingEndTime = StrToTime(todayDate + " 17:15");

   ObjectDelete(0, "RangeHigh");
   ObjectDelete(0, "RangeLow");
   ObjectDelete(0, "TradingWindow");
   ObjectDelete(0, "BreakoutCandle");

   CheckNewsToday();
}

//+------------------------------------------------------------------+
void UpdateRange()
{
   for(int i = 1; i < 300; i++)
   {
      datetime barTime = iTime(Symbol(), PERIOD_M1, i);
      int barHour = TimeHour(barTime);

      if(barHour >= 9 && barHour < 14)
      {
         double high = iHigh(Symbol(), PERIOD_M1, i);
         double low = iLow(Symbol(), PERIOD_M1, i);

         if(high > rangeHigh) rangeHigh = high;
         if(low < rangeLow) rangeLow = low;
      }
   }
}

//+------------------------------------------------------------------+
void FinalizeRange()
{
   if(rangeHigh > 0 && rangeLow < 999999)
   {
      rangeSet = true;
      Print("╔══════════════════════════════════════════════════╗");
      Print("║            RANGO ESTABLECIDO                     ║");
      Print("╚══════════════════════════════════════════════════╝");
      Print("Range High: ", rangeHigh);
      Print("Range Low: ", rangeLow);
      Print("Range Size: ", CalculatePips(rangeHigh - rangeLow), " pips");

      DrawRangeLines();

      if(EnableAlerts)
      {
         Alert("✅ Rango establecido");
      }
   }
}

//+------------------------------------------------------------------+
void DrawRangeLines()
{
   ObjectDelete(0, "RangeHigh");
   ObjectCreate(0, "RangeHigh", OBJ_HLINE, 0, 0, rangeHigh);
   ObjectSetInteger(0, "RangeHigh", OBJPROP_COLOR, clrDodgerBlue);
   ObjectSetInteger(0, "RangeHigh", OBJPROP_WIDTH, 2);

   ObjectDelete(0, "RangeLow");
   ObjectCreate(0, "RangeLow", OBJ_HLINE, 0, 0, rangeLow);
   ObjectSetInteger(0, "RangeLow", OBJPROP_COLOR, clrOrangeRed);
   ObjectSetInteger(0, "RangeLow", OBJPROP_WIDTH, 2);

   ObjectDelete(0, "TradingWindow");
   ObjectCreate(0, "TradingWindow", OBJ_RECTANGLE, 0, tradingStartTime, rangeHigh, tradingEndTime, rangeLow);
   ObjectSetInteger(0, "TradingWindow", OBJPROP_COLOR, clrGray);
   ObjectSetInteger(0, "TradingWindow", OBJPROP_BACK, true);
}

//+------------------------------------------------------------------+
void ProcessNewCandle()
{
   double open1 = iOpen(Symbol(), PERIOD_M1, 1);
   double close1 = iClose(Symbol(), PERIOD_M1, 1);
   double high1 = iHigh(Symbol(), PERIOD_M1, 1);
   double low1 = iLow(Symbol(), PERIOD_M1, 1);
   datetime time1 = iTime(Symbol(), PERIOD_M1, 1);

   bool isBullish = close1 > open1;
   bool isBearish = close1 < open1;

   if(!breakoutDetected)
   {
      if(rangeHigh >= low1 && rangeHigh <= high1 && isBullish)
      {
         attemptNumber++;
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = 1;
         breakoutSL = low1;
         candlesAfterBreakout = 0;

         Print("╔══════════════════════════════════════════════════╗");
         Print("║  INTENTO #", attemptNumber, " - RUPTURA ALCISTA               ║");
         Print("╚══════════════════════════════════════════════════╝");
         Print("Esperando 2 velas alcistas más...");

         MarkBreakoutCandle(time1, rangeHigh);

         if(EnableAlerts) Alert("🎯 Intento #", attemptNumber, " - Ruptura ALCISTA");

         return;
      }

      if(rangeLow >= low1 && rangeLow <= high1 && isBearish)
      {
         attemptNumber++;
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = -1;
         breakoutSL = high1;
         candlesAfterBreakout = 0;

         Print("╔══════════════════════════════════════════════════╗");
         Print("║  INTENTO #", attemptNumber, " - RUPTURA BAJISTA                ║");
         Print("╚══════════════════════════════════════════════════╝");
         Print("Esperando 2 velas bajistas más...");

         MarkBreakoutCandle(time1, rangeLow);

         if(EnableAlerts) Alert("🎯 Intento #", attemptNumber, " - Ruptura BAJISTA");

         return;
      }
   }

   if(breakoutDetected && !tradeExecutedToday)
   {
      candlesAfterBreakout++;

      Print("Vela ", (candlesAfterBreakout + 1), " - Esperado: ", (breakoutType == 1 ? "ALCISTA" : "BAJISTA"), 
            " | Actual: ", (isBullish ? "alcista" : (isBearish ? "bajista" : "doji")));

      if(breakoutType == 1 && !isBullish)
      {
         Print("❌ INTENTO #", attemptNumber, " CANCELADO - Vela NO alcista");
         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");
         if(EnableAlerts) Alert("❌ Intento cancelado");
         return;
      }

      if(breakoutType == -1 && !isBearish)
      {
         Print("❌ INTENTO #", attemptNumber, " CANCELADO - Vela NO bajista");
         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");
         if(EnableAlerts) Alert("❌ Intento cancelado");
         return;
      }

      Print("  ✓ Vela válida - Contador: ", candlesAfterBreakout, "/2");

      if(candlesAfterBreakout == 2)
      {
         double breakoutHigh = iHigh(Symbol(), PERIOD_M1, 3);
         double breakoutLow = iLow(Symbol(), PERIOD_M1, 3);
         double currentHigh = high1;
         double currentLow = low1;

         double totalMove;

         if(breakoutType == 1)
            totalMove = CalculatePips(currentHigh - breakoutLow);
         else
            totalMove = CalculatePips(breakoutHigh - currentLow);

         Print("╔══════════════════════════════════════════════════╗");
         Print("║  3 VELAS COMPLETADAS - INTENTO #", attemptNumber, "           ║");
         Print("╚══════════════════════════════════════════════════╝");
         Print("Movimiento total: ", totalMove, " pips");
         Print("Máximo permitido: ", MaxPipsMove, " pips");

         if(totalMove <= MaxPipsMove)
         {
            Print("✅ Movimiento válido - Procediendo a ejecutar orden...");
            Print("");
            Print("=== INFORMACIÓN PRE-EJECUCIÓN ===");
            Print("Tipo: ", (breakoutType == 1 ? "COMPRA" : "VENTA"));
            Print("SL: ", breakoutSL);
            Print("Precio actual (Ask): ", Ask);
            Print("Precio actual (Bid): ", Bid);
            Print("Balance: $", AccountBalance());
            Print("Margen libre: $", AccountFreeMargin());
            Print("tradeExecutedToday: ", tradeExecutedToday);
            Print("");

            if(breakoutType == 1)
               ExecuteBuyOrder(breakoutSL);
            else
               ExecuteSellOrder(breakoutSL);
         }
         else
         {
            Print("❌ ENTRADA ANULADA - Movimiento: ", totalMove, " > ", MaxPipsMove);
            if(EnableAlerts) Alert("⚠️ Entrada anulada - Movimiento excesivo");
         }

         breakoutDetected = false;
         ObjectDelete(0, "BreakoutCandle");
      }
   }
}

//+------------------------------------------------------------------+
void MarkBreakoutCandle(datetime time, double price)
{
   ObjectDelete(0, "BreakoutCandle");
   ObjectCreate(0, "BreakoutCandle", OBJ_ARROW, 0, time, price);
   ObjectSetInteger(0, "BreakoutCandle", OBJPROP_COLOR, clrYellow);
   ObjectSetInteger(0, "BreakoutCandle", OBJPROP_ARROWCODE, 108);
   ObjectSetInteger(0, "BreakoutCandle", OBJPROP_WIDTH, 4);
}

//+------------------------------------------------------------------+
double CalculatePips(double priceDistance)
{
   double pips = priceDistance / Point;

   if(StringFind(Symbol(), "US30") >= 0 || StringFind(Symbol(), "DOW") >= 0)
      pips = pips / 10.0;

   return pips;
}

//+------------------------------------------------------------------+
void ExecuteBuyOrder(double sl)
{
   Print("╔══════════════════════════════════════════════════╗");
   Print("║         EJECUTANDO ORDEN DE COMPRA              ║");
   Print("╚══════════════════════════════════════════════════╝");

   double entryPrice = Ask;
   double slDistance = entryPrice - sl;
