   Print("║              NUEVO DÍA DE TRADING                ║");
   Print("╚══════════════════════════════════════════════════╝");
   Print("Fecha UTC: ", TimeToString(GetUTCTime(), TIME_DATE));

   lastTradeDate = GetUTCTime();
   rangeHigh = 0;
   rangeLow = 999999;
   rangeSet = false;
   tradingWindowActive = false;
   tradeExecutedToday = false;
   slMovedToBE = false;

   breakoutDetected = false;
   breakoutCandleTime = 0;
   breakoutType = 0;
   breakoutSL = 0;
   candlesAfterBreakout = 0;
   attemptNumber = 0;

   // Horarios en hora del servidor
   string todayDate = TimeToString(TimeCurrent(), TIME_DATE);
   rangeStartTime = StrToTime(todayDate + " " + IntegerToString(GetServerHour(9)) + ":00");
   rangeEndTime = StrToTime(todayDate + " " + IntegerToString(GetServerHour(14)) + ":00");
   tradingStartTime = StrToTime(todayDate + " " + IntegerToString(GetServerHour(14)) + ":30");
   tradingEndTime = StrToTime(todayDate + " " + IntegerToString(GetServerHour(17)) + ":15");

