//+------------------------------------------------------------------+
void ProcessNewCandle()
{
   double open1 = iOpen(Symbol(), PERIOD_M1, 1);
   double close1 = iClose(Symbol(), PERIOD_M1, 1);
   double high1 = iHigh(Symbol(), PERIOD_M1, 1);
   double low1 = iLow(Symbol(), PERIOD_M1, 1);
   datetime time1 = iTime(Symbol(), PERIOD_M1, 1);

   bool isBullish = close1 > open1;
   bool isBearish = close1 < open1;

   if(!breakoutDetected)
   {
      if(rangeHigh >= low1 && rangeHigh <= high1 && isBullish)
      {
         attemptNumber++;
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = 1;
         breakoutSL = low1;
         candlesAfterBreakout = 0;

         datetime utcTime = time1 - ServerTimeOffset * 3600;

         Print("╔══════════════════════════════════════════════════╗");
         Print("║  INTENTO #", attemptNumber, " - RUPTURA ALCISTA               ║");
         Print("╚══════════════════════════════════════════════════╝");
         Print("Hora UTC: ", TimeToString(utcTime, TIME_MINUTES));
         Print("Hora Servidor: ", TimeToString(time1, TIME_MINUTES));
         Print("rangeHigh (", rangeHigh, ") dentro de vela [", low1, " - ", high1, "]");
         Print("Esperando 2 velas alcistas más...");

         MarkBreakoutCandle(time1, rangeHigh);

         if(EnableAlerts) Alert("🎯 Intento #", attemptNumber, " - Ruptura ALCISTA");

         return;
      }

      if(rangeLow >= low1 && rangeLow <= high1 && isBearish)
      {
         attemptNumber++;
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = -1;
         breakoutSL = high1;
         candlesAfterBreakout = 0;

         datetime utcTime = time1 - ServerTimeOffset * 3600;

         Print("╔══════════════════════════════════════════════════╗");
         Print("║  INTENTO #", attemptNumber, " - RUPTURA BAJISTA                ║");
         Print("╚══════════════════════════════════════════════════╝");
         Print("Hora UTC: ", TimeToString(utcTime, TIME_MINUTES));
         Print("Hora Servidor: ", TimeToString(time1, TIME_MINUTES));
         Print("rangeLow (", rangeLow, ") dentro de vela [", low1, " - ", high1, "]");
         Print("Esperando 2 velas bajistas más...");

         MarkBreakoutCandle(time1, rangeLow);

         if(EnableAlerts) Alert("🎯 Intento #", attemptNumber, " - Ruptura BAJISTA");

         return;
      }
   }

   if(breakoutDetected && !tradeExecutedToday)
   {
      candlesAfterBreakout++;

      Print("Vela ", (candlesAfterBreakout + 1), " - Esperado: ", (breakoutType == 1 ? "ALCISTA" : "BAJISTA"),
            " | Actual: ", (isBullish ? "alcista" : (isBearish ? "bajista" : "doji")));

      if(breakoutType == 1 && !isBullish)
      {
         Print("❌ INTENTO #", attemptNumber, " CANCELADO - Vela NO alcista");
         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");
         if(EnableAlerts) Alert("❌ Intento cancelado");
         return;
      }

      if(breakoutType == -1 && !isBearish)
      {
         Print("❌ INTENTO #", attemptNumber, " CANCELADO - Vela NO bajista");
         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");
         if(EnableAlerts) Alert("❌ Intento cancelado");
         return;
      }

      Print("  ✓ Vela válida - Contador: ", candlesAfterBreakout, "/2");

      if(candlesAfterBreakout == 2)
      {
         double breakoutHigh = iHigh(Symbol(), PERIOD_M1, 3);
         double breakoutLow = iLow(Symbol(), PERIOD_M1, 3);
         double currentHigh = high1;
         double currentLow = low1;

         double totalMove;

         if(breakoutType == 1)
            totalMove = CalculatePips(currentHigh - breakoutLow);
         else
            totalMove = CalculatePips(breakoutHigh - currentLow);

         Print("╔══════════════════════════════════════════════════╗");
         Print("║  INTENTO #", attemptNumber, " COMPLETADO                      ║");
         Print("║  3 VELAS CONSECUTIVAS VÁLIDAS                   ║");
         Print("╚══════════════════════════════════════════════════╝");
         Print("Movimiento total: ", totalMove, " pips");

         if(totalMove <= MaxPipsMove)
         {
            if(breakoutType == 1)
               ExecuteBuyOrder(breakoutSL);
            else
               ExecuteSellOrder(breakoutSL);
         }
         else
         {
            Print("⚠️ ENTRADA ANULADA - Movimiento: ", totalMove, " > ", MaxPipsMove);
            if(EnableAlerts)
               Alert("⚠️ Entrada anulada - Movimiento excesivo");
         }

         breakoutDetected = false;
         ObjectDelete(0, "BreakoutCandle");
      }
   }
}

//+------------------------------------------------------------------+
void MarkBreakoutCandle(datetime time, double price)
{
   ObjectDelete(0, "BreakoutCandle");
   ObjectCreate(0, "BreakoutCandle", OBJ_ARROW, 0, time, price);
   ObjectSetInteger(0, "BreakoutCandle", OBJPROP_COLOR, clrYellow);
   ObjectSetInteger(0, "BreakoutCandle", OBJPROP_ARROWCODE, 108);
   ObjectSetInteger(0, "BreakoutCandle", OBJPROP_WIDTH, 4);
}

//+------------------------------------------------------------------+
double CalculatePips(double priceDistance)
{
   double pips = priceDistance / Point;

   if(StringFind(Symbol(), "US30") >= 0 || StringFind(Symbol(), "DOW") >= 0)
      pips = pips / 10.0;

   return pips;
}

//+------------------------------------------------------------------+
void ExecuteBuyOrder(double sl)
{
   double entryPrice = Ask;
   double tp = entryPrice + (entryPrice - sl);

   double lotSize = CalculateLotSize(sl, OP_BUY);

   if(lotSize > 0)
   {
      int ticket = OrderSend(Symbol(), OP_BUY, lotSize, Ask, Slippage, sl, tp, 
                            "US30_Final", MagicNumber, 0, clrGreen);

      if(ticket > 0)
      {
         tradeExecutedToday = true;
         slMovedToBE = false;

         Print("╔══════════════════════════════════════════════════╗");
         Print("║           COMPRA EJECUTADA ✅                    ║");
         Print("╚══════════════════════════════════════════════════╝");
         Print("Intento exitoso: #", attemptNumber);
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
         Print("Entry: ", Ask, " | SL: ", sl, " | TP: ", tp);
         Print("Riesgo: $", RiskAmount);
         Print("BE: ", BEPercent, "% con +", BEProfitPercent, "%");

         if(EnableAlerts)
            Alert("✅ COMPRA ejecutada - Ticket: ", ticket);
      }
      else
      {
         Print("❌ ERROR al abrir COMPRA: ", GetLastError());
      }
   }
}

//+------------------------------------------------------------------+
void ExecuteSellOrder(double sl)
{
   double entryPrice = Bid;
   double tp = entryPrice - (sl - entryPrice);

   double lotSize = CalculateLotSize(sl, OP_SELL);

   if(lotSize > 0)
   {
      int ticket = OrderSend(Symbol(), OP_SELL, lotSize, Bid, Slippage, sl, tp, 
                            "US30_Final", MagicNumber, 0, clrRed);

      if(ticket > 0)
      {
         tradeExecutedToday = true;
         slMovedToBE = false;

         Print("╔══════════════════════════════════════════════════╗");
         Print("║           VENTA EJECUTADA ✅                     ║");
         Print("╚══════════════════════════════════════════════════╝");
         Print("Intento exitoso: #", attemptNumber);
         Print("Ticket: ", ticket);
         Print("Lotes: ", lotSize);
         Print("Entry: ", Bid, " | SL: ", sl, " | TP: ", tp);
         Print("Riesgo: $", RiskAmount);
         Print("BE: ", BEPercent, "% con +", BEProfitPercent, "%");

         if(EnableAlerts)
            Alert("✅ VENTA ejecutada - Ticket: ", ticket);
      }
      else
      {
         Print("❌ ERROR al abrir VENTA: ", GetLastError());
      }
   }
}

//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice, int orderType)
{
   double slDistance;

   if(orderType == OP_BUY)
      slDistance = Ask - slPrice;
   else
      slDistance = slPrice - Bid;

   if(slDistance <= 0) return 0;

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);

   if(tickValue == 0 || tickSize == 0) return 0;

   double lotSize = (RiskAmount / (slDistance / tickSize * tickValue));

   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = NormalizeDouble(lotSize, 2);
   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   return lotSize;
}

//+------------------------------------------------------------------+
void ManageOpenTrades()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;

      if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
      {
         double openPrice = OrderOpenPrice();
         double sl = OrderStopLoss();
         double tp = OrderTakeProfit();

         if(OrderType() == OP_BUY)
         {
            double distance = tp - openPrice;
            double triggerPrice = openPrice + (distance * BEPercent / 100.0);
            double profitDistance = distance * (BEProfitPercent / 100.0);
            double newSL = openPrice + profitDistance;

            if(Bid >= triggerPrice && sl < newSL && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, newSL, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("╔══════════════════════════════════════════════════╗");
                  Print("║       SL MOVIDO A BE + ", BEProfitPercent, "%                    ║");
                  Print("╚══════════════════════════════════════════════════╝");
                  Print("Nuevo SL: ", newSL);
                  Print("Ganancia asegurada: ", CalculatePips(newSL - openPrice), " pips");

                  if(EnableAlerts)
                     Alert("✅ SL en BE+", BEProfitPercent, "%");
               }
            }
         }
         else if(OrderType() == OP_SELL)
         {
            double distance = openPrice - tp;
            double triggerPrice = openPrice - (distance * BEPercent / 100.0);
            double profitDistance = distance * (BEProfitPercent / 100.0);
            double newSL = openPrice - profitDistance;

            if(Ask <= triggerPrice && sl > newSL && !slMovedToBE)
            {
               bool result = OrderModify(OrderTicket(), openPrice, newSL, tp, 0, clrBlue);

               if(result)
               {
                  slMovedToBE = true;
                  Print("╔══════════════════════════════════════════════════╗");
                  Print("║       SL MOVIDO A BE + ", BEProfitPercent, "%                    ║");
                  Print("╚══════════════════════════════════════════════════╝");
                  Print("Nuevo SL: ", newSL);
                  Print("Ganancia asegurada: ", CalculatePips(openPrice - newSL), " pips");

                  if(EnableAlerts)
                     Alert("✅ SL en BE+", BEProfitPercent, "%");
               }
            }
         }
      }
   }
}

