string GetErrorDescription(int errorCode)
{
   switch(errorCode)
   {
      case 0:    return "Sin error";
      case 1:    return "Sin error pero resultado desconocido";
      case 2:    return "Error común";
      case 3:    return "Parámetros incorrectos";
      case 4:    return "Servidor ocupado";
      case 130:  return "Stops inválidos";
      case 131:  return "Volumen inválido";
      case 132:  return "Mercado cerrado";
      case 133:  return "Trading deshabilitado";
      case 134:  return "Fondos insuficientes";
      case 135:  return "Precio cambió";
      case 138:  return "Requote";
      default:   return "Error " + IntegerToString(errorCode);
   }
}
