            info += "   Estado: " + candle2Status + "\n";
            info += "   High: " + DoubleToString(candle2High, Digits) + "\n";
            info += "   Low: " + DoubleToString(candle2Low, Digits) + "\n";
         }
      }
      else
      {
         info += "   Estado: --\n";
      }
      info += "\n";

      info += "📍 VELA 3:\n";
      if(candle3Status != "")
      {
         if(candle3Status == "Esperando...")
         {
            info += "   Estado: ⏳ Esperando...\n";
         }
         else
         {
            info += "   Estado: " + candle3Status + "\n";
            info += "   High: " + DoubleToString(candle3High, Digits) + "\n";
            info += "   Low: " + DoubleToString(candle3Low, Digits) + "\n";
            info += "\n";
            info += "   🚀 3 VELAS COMPLETADAS!\n";
            info += "   → Verificando movimiento...\n";
         }
      }
      else
      {
         info += "   Estado: --\n";
      }
      info += "\n";
   }

   info += "💰 CUENTA:\n";
   info += "   Balance: $" + DoubleToString(AccountBalance(), 2) + "\n";
   info += "   Equity: $" + DoubleToString(AccountEquity(), 2) + "\n\n";

   for(int i = 0; i < OrdersTotal(); i++)
   {
      if(OrderSelect(i, SELECT_BY_POS, MODE_TRADES))
      {
         if(OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber)
         {
            info += "📈 POSICIÓN:\n";
            info += "   #" + IntegerToString(OrderTicket()) + " | ";
            info += (OrderType() == OP_BUY ? "COMPRA" : "VENTA") + "\n";
            info += "   Profit: $" + DoubleToString(OrderProfit(), 2) + "\n";
            info += "   SL en BE: " + (slMovedToBE ? "✓" : "✗") + "\n";
         }
      }
   }

   info += "\n╚═══════════════════════════════════════════════════════════╝";

   Comment(info);
}

//+------------------------------------------------------------------+
string GetErrorDescription(int errorCode)
{
   switch(errorCode)
   {
      case 0:    return "Sin error";
      case 130:  return "Stops inválidos";
      case 131:  return "Volumen inválido";
      case 132:  return "Mercado cerrado";
      case 133:  return "Trading deshabilitado";
      case 134:  return "Fondos insuficientes";
      case 135:  return "Precio cambió";
      case 138:  return "Requote";
      default:   return "Error " + IntegerToString(errorCode);
   }
}
