         Print("  Range Low ", rangeLow, " dentro de [", low1, " - ", high1, "]");
         Print("Esperando 2 velas bajistas más...");

         MarkBreakoutCandle(time1, rangeLow);

         if(EnableAlerts) Alert("🎯 Intento #", attemptNumber, " - Ruptura BAJISTA");

         return;
      }
   }

   if(breakoutDetected && !tradeExecutedToday)
   {
      candlesAfterBreakout++;

      Print("VELA ", (candlesAfterBreakout + 1), ": ", TimeToString(time1, TIME_MINUTES));
      Print("  Esperado: ", (breakoutType == 1 ? "ALCISTA" : "BAJISTA"));
      Print("  Actual: ", (isBullish ? "alcista" : (isBearish ? "bajista" : "doji")));

      if(breakoutType == 1 && !isBullish)
      {
         Print("❌ CANCELADO - Vela NO alcista");
         candle1Status = "";
         candle2Status = "";
         candle3Status = "";
         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");
         if(EnableAlerts) Alert("❌ Intento cancelado");
         return;
      }

      if(breakoutType == -1 && !isBearish)
      {
         Print("❌ CANCELADO - Vela NO bajista");
         candle1Status = "";
         candle2Status = "";
         candle3Status = "";
         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");
         if(EnableAlerts) Alert("❌ Intento cancelado");
         return;
      }

      // Actualizar visual
      if(candlesAfterBreakout == 1)
      {
         candle2Status = (breakoutType == 1 ? "ALCISTA ✓" : "BAJISTA ✓");
         candle2High = high1;
         candle2Low = low1;
         candle3Status = "Esperando...";
         Print("  ✓ VELA 2 válida");
      }
      else if(candlesAfterBreakout == 2)
      {
         candle3Status = (breakoutType == 1 ? "ALCISTA ✓" : "BAJISTA ✓");
         candle3High = high1;
         candle3Low = low1;
         Print("  ✓ VELA 3 válida");
      }

      if(candlesAfterBreakout == 2)
      {
         double breakoutHigh = iHigh(Symbol(), PERIOD_M1, 3);
         double breakoutLow = iLow(Symbol(), PERIOD_M1, 3);
         double currentHigh = high1;
         double currentLow = low1;

         double totalMove;

         if(breakoutType == 1)
            totalMove = CalculatePips(currentHigh - breakoutLow);
         else
            totalMove = CalculatePips(breakoutHigh - currentLow);

         Print("╔══════════════════════════════════════════════════╗");
         Print("║  3 VELAS COMPLETADAS - INTENTO #", attemptNumber, "           ║");
         Print("╚══════════════════════════════════════════════════╝");
         Print("Movimiento total: ", totalMove, " pips");
         Print("Ask: ", Ask, " | Bid: ", Bid);
         Print("Balance: $", AccountBalance());
         Print("Margen libre: $", AccountFreeMargin());

         if(totalMove <= MaxPipsMove)
         {
            Print("✅ Movimiento válido - EJECUTANDO ORDEN...");

            if(breakoutType == 1)
               ExecuteBuyOrder(breakoutSL);
            else
               ExecuteSellOrder(breakoutSL);
         }
         else
         {
            Print("❌ ENTRADA ANULADA - Movimiento excesivo");
            if(EnableAlerts) Alert("⚠️ Movimiento excesivo");
         }

         // Reset visual después de intentar ejecutar
         candle1Status = "";
         candle2Status = "";
         candle3Status = "";
         breakoutDetected = false;
         ObjectDelete(0, "BreakoutCandle");
      }
   }
}

