      return;
   }

   string todayDateUTC = TimeToString(GetUTCTime(), TIME_DATE);
   newsEventTime = StrToTime(todayDateUTC + " " + NewsTime) + ServerTimeOffset * 3600;
   newsEventToday = true;
}

