//+------------------------------------------------------------------+
int OnInit()
{
   Print("╔══════════════════════════════════════════════════╗");
   Print("║  US30 RANGE BREAKOUT - VERSIÓN 5.0 DEBUG        ║");
   Print("╚══════════════════════════════════════════════════╝");

