//+------------------------------------------------------------------+
void DetectTimezone()
{
   // Detectar offset basado en la hora del broker
   // Asumiendo que la mayoría de brokers están en UTC+2 o UTC+3
   int serverHour = TimeHour(TimeCurrent());

   // Si no se especificó, intentar detectar
   // La mayoría de brokers europeos usan UTC+2 (verano) o UTC+3 (Rusia)
   detectedOffset = 2; // Por defecto UTC+2
   offsetDetected = true;

   Print("⚠️ AUTO-DETECCIÓN: Asumiendo UTC+2");
   Print("⚠️ Si los horarios no son correctos, configura ServerTimeOffset manualmente");
}

//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   ObjectDelete(0, "RangeHigh");
   ObjectDelete(0, "RangeLow");
   ObjectDelete(0, "TradingWindow");
   ObjectDelete(0, "BreakoutCandle");
   Comment("");
}

//+------------------------------------------------------------------+
datetime GetUTCTime()
{
   return TimeCurrent() - detectedOffset * 3600;
}

//+------------------------------------------------------------------+
int GetUTCHour()
{
   return TimeHour(GetUTCTime());
}

//+------------------------------------------------------------------+
int GetUTCMinute()
{
   return TimeMinute(GetUTCTime());
}

//+------------------------------------------------------------------+
int GetServerHour(int utcHour)
{
   int serverHour = utcHour + detectedOffset;
   if(serverHour >= 24) serverHour -= 24;
   if(serverHour < 0) serverHour += 24;
   return serverHour;
}

//+------------------------------------------------------------------+
void OnTick()
{
   datetime utcTime = GetUTCTime();

   if(TimeDayOfYear(utcTime) != TimeDayOfYear(lastTradeDate))
   {
      ResetDaily();
   }

   int utcHour = GetUTCHour();
   int utcMinute = GetUTCMinute();

   // Establecer rango 9:00 - 14:00 UTC
   if(utcHour >= 9 && utcHour < 14)
   {
      UpdateRange();
   }

   // Finalizar rango a las 14:00 UTC
   if(utcHour == 14 && utcMinute == 0 && !rangeSet)
   {
      FinalizeRange();
   }

   // FORZAR finalización si ya pasó las 14:00 y aún no está set
   if(utcHour >= 14 && !rangeSet && rangeHigh > 0)
   {
      FinalizeRange();
   }

   // Ventana de trading 15:30 - 17:30 UTC
   tradingWindowActive = false;
   if((utcHour == 15 && utcMinute >= 30) || 
      (utcHour == 16) ||
      (utcHour == 17 && utcMinute <= 30))
   {
      tradingWindowActive = true;

      if(UseNewsFilter && newsEventToday && utcTime < newsEventTime)
      {
         tradingWindowActive = false;
         return;
      }
   }

   // Verificar nueva vela
   datetime currentCandleTime = iTime(Symbol(), PERIOD_M1, 0);
   if(currentCandleTime != lastCandleTime)
   {
      lastCandleTime = currentCandleTime;

      if(tradingWindowActive && rangeSet && !tradeExecutedToday)
      {
         ProcessNewCandle();
      }
   }

   ManageOpenTrades();
   UpdateDisplay();
}

//+------------------------------------------------------------------+
void ResetDaily()
{
   Print("╔══════════════════════════════════════════════════╗");
   Print("║              NUEVO DÍA - RESET COMPLETO          ║");
   Print("╚══════════════════════════════════════════════════╝");

   lastTradeDate = GetUTCTime();
   rangeHigh = 0;
   rangeLow = 999999;
   rangeSet = false;
   tradingWindowActive = false;
   tradeExecutedToday = false;
   slMovedToBE = false;

   breakoutDetected = false;
   breakoutCandleTime = 0;
   breakoutType = 0;
   breakoutSL = 0;
   candlesAfterBreakout = 0;
   attemptNumber = 0;

   candle1Status = "";
   candle2Status = "";
   candle3Status = "";

   string todayDate = TimeToString(TimeCurrent(), TIME_DATE);
   rangeStartTime = StrToTime(todayDate + " " + IntegerToString(GetServerHour(9)) + ":00");
   rangeEndTime = StrToTime(todayDate + " " + IntegerToString(GetServerHour(14)) + ":00");
   tradingStartTime = StrToTime(todayDate + " " + IntegerToString(GetServerHour(15)) + ":30");
   tradingEndTime = StrToTime(todayDate + " " + IntegerToString(GetServerHour(17)) + ":30");

   Print("Horarios del día (hora del servidor):");
   Print("  Rango: ", TimeToString(rangeStartTime, TIME_MINUTES), " - ", TimeToString(rangeEndTime, TIME_MINUTES));
   Print("  Trading: ", TimeToString(tradingStartTime, TIME_MINUTES), " - ", TimeToString(tradingEndTime, TIME_MINUTES));

   ObjectDelete(0, "RangeHigh");
   ObjectDelete(0, "RangeLow");
   ObjectDelete(0, "TradingWindow");
   ObjectDelete(0, "BreakoutCandle");

   CheckNewsToday();

   // Actualizar rango inmediatamente si estamos en período de rango
   int utcHour = GetUTCHour();
   if(utcHour >= 9 && utcHour < 14)
   {
      Print("⚠️ Estamos EN período de rango - Actualizando...");
      UpdateRange();
   }
   else if(utcHour >= 14)
   {
      Print("⚠️ Ya pasó el período de rango - Actualizando histórico...");
      UpdateRange();
      if(rangeHigh > 0 && rangeLow < 999999)
      {
         FinalizeRange();
      }
   }
}

//+------------------------------------------------------------------+
void UpdateRange()
{
   int barsChecked = 0;
   int barsInRange = 0;

   for(int i = 1; i < 600; i++) // Aumentado a 600 (10 horas)
   {
      datetime barTime = iTime(Symbol(), PERIOD_M1, i);
      if(barTime == 0) break;

      datetime utcBarTime = barTime - detectedOffset * 3600;
      int barUtcHour = TimeHour(utcBarTime);

      barsChecked++;

      if(barUtcHour >= 9 && barUtcHour < 14)
      {
         barsInRange++;
         double high = iHigh(Symbol(), PERIOD_M1, i);
         double low = iLow(Symbol(), PERIOD_M1, i);

         if(high > rangeHigh) rangeHigh = high;
         if(low < rangeLow) rangeLow = low;
      }
   }

   // Debug: mostrar cada 60 ticks
   static int tickCount = 0;
   tickCount++;
   if(tickCount % 60 == 0)
   {
      Print("UpdateRange: Barras revisadas=", barsChecked, ", En rango=", barsInRange, 
            ", High=", rangeHigh, ", Low=", rangeLow);
   }
}

//+------------------------------------------------------------------+
void FinalizeRange()
{
   if(rangeHigh > 0 && rangeLow < 999999 && (rangeHigh - rangeLow) > 0)
   {
      rangeSet = true;
      Print("╔══════════════════════════════════════════════════╗");
      Print("║         ✅ RANGO ESTABLECIDO ✅                  ║");
      Print("╚══════════════════════════════════════════════════╝");
      Print("Range High: ", rangeHigh);
      Print("Range Low: ", rangeLow);
      Print("Range Size: ", CalculatePips(rangeHigh - rangeLow), " pips");
      Print("Hora UTC: ", TimeToString(GetUTCTime(), TIME_MINUTES));

      DrawRangeLines();

      if(EnableAlerts)
      {
         Alert("✅ RANGO ESTABLECIDO - ", CalculatePips(rangeHigh - rangeLow), " pips");
      }
   }
   else
   {
      Print("⚠️⚠️⚠️ NO SE PUDO ESTABLECER EL RANGO ⚠️⚠️⚠️");
      Print("rangeHigh: ", rangeHigh);
      Print("rangeLow: ", rangeLow);
      Print("Diferencia: ", (rangeHigh - rangeLow));
      Alert("⚠️ ERROR: No se pudo establecer el rango. Revisa los logs.");
   }
}

//+------------------------------------------------------------------+
void DrawRangeLines()
{
   ObjectDelete(0, "RangeHigh");
