   ObjectSetInteger(0, "RangeHigh", OBJPROP_COLOR, clrDodgerBlue);
   ObjectSetInteger(0, "RangeHigh", OBJPROP_WIDTH, 3);
   ObjectSetInteger(0, "RangeHigh", OBJPROP_STYLE, STYLE_SOLID);

   ObjectDelete(0, "RangeLow");
