      Print("║    ❌❌❌ ERROR EN VENTA ❌❌❌                 ║");
      Print("╚══════════════════════════════════════════════════╝");
      Print("Error Code: ", error);
      Print("Error: ", GetErrorDescription(error));

      Alert("❌ ERROR: ", error, " - ", GetErrorDescription(error));
   }
}

//+------------------------------------------------------------------+
double CalculateLotSize(double slPrice, int orderType)
{
   double slDistance = (orderType == OP_BUY) ? (Ask - slPrice) : (slPrice - Bid);
   if(slDistance <= 0) return 0;

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);
   if(tickValue == 0 || tickSize == 0) return 0;

   double lotSize = (RiskAmount / (slDistance / tickSize * tickValue));

   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = NormalizeDouble(lotSize, 2);
   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   return lotSize;
}

//+------------------------------------------------------------------+
void ManageOpenTrades()
{
   for(int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if(!OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) continue;
      if(OrderSymbol() != Symbol() || OrderMagicNumber() != MagicNumber) continue;

      double openPrice = OrderOpenPrice();
      double sl = OrderStopLoss();
      double tp = OrderTakeProfit();

      if(OrderType() == OP_BUY)
      {
         double distance = tp - openPrice;
         double triggerPrice = openPrice + (distance * BEPercent / 100.0);
         double newSL = openPrice + (distance * BEProfitPercent / 100.0);

         if(Bid >= triggerPrice && sl < newSL && !slMovedToBE)
         {
            if(OrderModify(OrderTicket(), openPrice, newSL, tp, 0, clrBlue))
            {
               slMovedToBE = true;
               Print("✅ SL movido a BE+", BEProfitPercent, "%");
               if(EnableAlerts) Alert("✅ SL en BE");
            }
         }
      }
      else if(OrderType() == OP_SELL)
      {
         double distance = openPrice - tp;
         double triggerPrice = openPrice - (distance * BEPercent / 100.0);
         double newSL = openPrice - (distance * BEProfitPercent / 100.0);

         if(Ask <= triggerPrice && sl > newSL && !slMovedToBE)
         {
            if(OrderModify(OrderTicket(), openPrice, newSL, tp, 0, clrBlue))
            {
               slMovedToBE = true;
               Print("✅ SL movido a BE+", BEProfitPercent, "%");
               if(EnableAlerts) Alert("✅ SL en BE");
            }
         }
      }
   }
}

