//+------------------------------------------------------------------+
void ProcessNewCandle()
{
   double open1 = iOpen(Symbol(), PERIOD_M1, 1);
   double close1 = iClose(Symbol(), PERIOD_M1, 1);
   double high1 = iHigh(Symbol(), PERIOD_M1, 1);
   double low1 = iLow(Symbol(), PERIOD_M1, 1);
   datetime time1 = iTime(Symbol(), PERIOD_M1, 1);

   bool isBullish = close1 > open1;
   bool isBearish = close1 < open1;

   if(!breakoutDetected)
   {
      candle1Status = "";
      candle2Status = "";
      candle3Status = "";

      if(rangeHigh >= low1 && rangeHigh <= high1 && isBullish)
      {
         attemptNumber++;
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = 1;
         breakoutSL = low1;
         candlesAfterBreakout = 0;

         candle1Status = "COMPRA";
         candle1High = high1;
         candle1Low = low1;
         candle2Status = "Esperando...";
         candle3Status = "Esperando...";

         Print("╔══════════════════════════════════════════════════╗");
         Print("║  INTENTO #", attemptNumber, " - RUPTURA ALCISTA               ║");
         Print("╚══════════════════════════════════════════════════╝");

         MarkBreakoutCandle(time1, rangeHigh);
         if(EnableAlerts) Alert("🎯 Ruptura ALCISTA");
         return;
      }

      if(rangeLow >= low1 && rangeLow <= high1 && isBearish)
      {
         attemptNumber++;
         breakoutDetected = true;
         breakoutCandleTime = time1;
         breakoutType = -1;
         breakoutSL = high1;
         candlesAfterBreakout = 0;

         candle1Status = "VENTA";
         candle1High = high1;
         candle1Low = low1;
         candle2Status = "Esperando...";
         candle3Status = "Esperando...";

         Print("╔══════════════════════════════════════════════════╗");
         Print("║  INTENTO #", attemptNumber, " - RUPTURA BAJISTA                ║");
         Print("╚══════════════════════════════════════════════════╝");

         MarkBreakoutCandle(time1, rangeLow);
         if(EnableAlerts) Alert("🎯 Ruptura BAJISTA");
         return;
      }
   }

   if(breakoutDetected && !tradeExecutedToday)
   {
      candlesAfterBreakout++;

      if(breakoutType == 1 && !isBullish)
      {
         Print("❌ CANCELADO - Vela NO alcista");
         candle1Status = "";
         candle2Status = "";
         candle3Status = "";
         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");
         return;
      }

      if(breakoutType == -1 && !isBearish)
      {
         Print("❌ CANCELADO - Vela NO bajista");
         candle1Status = "";
         candle2Status = "";
         candle3Status = "";
         breakoutDetected = false;
         candlesAfterBreakout = 0;
         ObjectDelete(0, "BreakoutCandle");
         return;
      }

      if(candlesAfterBreakout == 1)
      {
         candle2Status = (breakoutType == 1 ? "ALCISTA ✓" : "BAJISTA ✓");
         candle2High = high1;
         candle2Low = low1;
         candle3Status = "Esperando...";
         Print("  ✓ VELA 2 válida");
      }
      else if(candlesAfterBreakout == 2)
      {
         candle3Status = (breakoutType == 1 ? "ALCISTA ✓" : "BAJISTA ✓");
         candle3High = high1;
         candle3Low = low1;
         Print("  ✓ VELA 3 válida");
      }

      if(candlesAfterBreakout == 2)
      {
         double breakoutHigh = iHigh(Symbol(), PERIOD_M1, 3);
         double breakoutLow = iLow(Symbol(), PERIOD_M1, 3);

         double totalMove = (breakoutType == 1) ? 
            CalculatePips(high1 - breakoutLow) : 
            CalculatePips(breakoutHigh - low1);

         Print("╔══════════════════════════════════════════════════╗");
         Print("║  3 VELAS COMPLETADAS                             ║");
         Print("╚══════════════════════════════════════════════════╝");
         Print("Movimiento: ", totalMove, " pips");

         if(totalMove <= MaxPipsMove)
         {
            if(breakoutType == 1)
               ExecuteBuyOrder(breakoutSL);
            else
               ExecuteSellOrder(breakoutSL);
         }
         else
         {
            Print("❌ Movimiento excesivo");
         }

         candle1Status = "";
         candle2Status = "";
         candle3Status = "";
         breakoutDetected = false;
         ObjectDelete(0, "BreakoutCandle");
      }
   }
}

