   string tradingStartTimeStr = IntegerToString(GetServerHour(tradingStartUTC)) + ":" + 
                                (tradingStartMinUTC < 10 ? "0" : "") + IntegerToString(tradingStartMinUTC);
   string tradingEndTimeStr = IntegerToString(GetServerHour(tradingEndUTC)) + ":" + 
                             (tradingEndMinUTC < 10 ? "0" : "") + IntegerToString(tradingEndMinUTC);

   tradingStartTime = StrToTime(todayDate + " " + tradingStartTimeStr);
   tradingEndTime = StrToTime(todayDate + " " + tradingEndTimeStr);

   ObjectDelete(0, "RangeHigh");
   ObjectDelete(0, "RangeLow");
   ObjectDelete(0, "TradingWindow");
   ObjectDelete(0, "BreakoutCandle");

   CheckNewsToday();

   // Actualizar rango si corresponde
   int utcHour = GetUTCHour();
   if(utcHour >= rangeStartUTC && utcHour < rangeEndUTC)
   {
      UpdateRange();
   }
   else if(utcHour >= rangeEndUTC)
   {
      UpdateRange();
      if(rangeHigh > 0 && rangeLow < 999999)
      {
         FinalizeRange();
      }
   }
}

//+------------------------------------------------------------------+
void UpdateRange()
{
   for(int i = 1; i < 600; i++)
   {
      datetime barTime = iTime(Symbol(), PERIOD_M1, i);
      if(barTime == 0) break;

      datetime utcBarTime = barTime - ServerTimeOffset * 3600;
      int barUtcHour = TimeHour(utcBarTime);

      if(barUtcHour >= rangeStartUTC && barUtcHour < rangeEndUTC)
      {
         double high = iHigh(Symbol(), PERIOD_M1, i);
         double low = iLow(Symbol(), PERIOD_M1, i);

         if(high > rangeHigh) rangeHigh = high;
         if(low < rangeLow) rangeLow = low;
      }
   }
}

//+------------------------------------------------------------------+
void FinalizeRange()
{
   if(rangeHigh > 0 && rangeLow < 999999 && (rangeHigh - rangeLow) > 0)
   {
      rangeSet = true;
      Print("╔══════════════════════════════════════════════════╗");
      Print("║         ✅ RANGO ESTABLECIDO ✅                  ║");
      Print("╚══════════════════════════════════════════════════╝");
      Print("Range High: ", rangeHigh);
      Print("Range Low: ", rangeLow);
      Print("Range Size: ", CalculatePips(rangeHigh - rangeLow), " pips");

      DrawRangeLines();

      if(EnableAlerts)
      {
         Alert("✅ RANGO ESTABLECIDO - ", CalculatePips(rangeHigh - rangeLow), " pips");
      }
   }
}

