double CalculateLotSize(double slPrice, int orderType)
{
   double slDistance = (orderType == OP_BUY) ? (Ask - slPrice) : (slPrice - Bid);
   if(slDistance <= 0)
   {
      Print("❌ ERROR: SL Distance <= 0");
      return 0;
   }

   double tickValue = MarketInfo(Symbol(), MODE_TICKVALUE);
   double tickSize = MarketInfo(Symbol(), MODE_TICKSIZE);
   if(tickValue == 0 || tickSize == 0)
   {
      Print("❌ ERROR: Tick value o size = 0");
      return 0;
   }

   double lotSize = (RiskAmount / (slDistance / tickSize * tickValue));

   double minLot = MarketInfo(Symbol(), MODE_MINLOT);
   double maxLot = MarketInfo(Symbol(), MODE_MAXLOT);
   double lotStep = MarketInfo(Symbol(), MODE_LOTSTEP);

   lotSize = NormalizeDouble(lotSize, 2);
   lotSize = MathFloor(lotSize / lotStep) * lotStep;
   lotSize = MathMax(minLot, MathMin(maxLot, lotSize));

   // VALIDACIÓN DE MARGEN
   double marginRequired = MarketInfo(Symbol(), MODE_MARGINREQUIRED) * lotSize;
   double freeMargin = AccountFreeMargin();

   Print("=== VALIDACIÓN DE MARGEN ===");
   Print("Lote calculado: ", lotSize);
   Print("Margen requerido: $", marginRequired);
   Print("Margen disponible: $", freeMargin);

   // Si no hay suficiente margen, reducir el lote
   if(marginRequired > freeMargin && freeMargin > 0)
   {
      Print("⚠️ Margen insuficiente - Ajustando lote...");

      // Calcular el lote máximo posible con el margen disponible
      double maxLotByMargin = (freeMargin * 0.9) / MarketInfo(Symbol(), MODE_MARGINREQUIRED);
      maxLotByMargin = NormalizeDouble(maxLotByMargin, 2);
      maxLotByMargin = MathFloor(maxLotByMargin / lotStep) * lotStep;
      maxLotByMargin = MathMax(minLot, maxLotByMargin);

      if(maxLotByMargin >= minLot)
      {
         lotSize = maxLotByMargin;
         Print("✅ Lote ajustado a: ", lotSize);
         Print("   Nuevo margen requerido: $", MarketInfo(Symbol(), MODE_MARGINREQUIRED) * lotSize);
         Print("   Riesgo ajustado: $", (slDistance / tickSize * tickValue) * lotSize);
      }
      else
      {
         Print("❌ ERROR: Margen insuficiente incluso para lote mínimo");
         Print("   Se requiere al menos: $", MarketInfo(Symbol(), MODE_MARGINREQUIRED) * minLot);
         Print("   Disponible: $", freeMargin);
         return 0;
      }
   }

   return lotSize;
}

