void UpdateRange()
{
   int barsChecked = 0;
   int barsInRange = 0;

   Print("════════════════════════════════════════");
   Print("ACTUALIZANDO RANGO...");
   Print("════════════════════════════════════════");
   Print("Buscando barras entre ", rangeStartUTC, ":00 - ", rangeEndUTC, ":00 UTC");
   Print("Valores actuales: High=", rangeHigh, " Low=", rangeLow);

   for(int i = 1; i < 600; i++)
   {
      datetime barTime = iTime(Symbol(), PERIOD_M1, i);
      if(barTime == 0) break;

      barsChecked++;

      datetime utcBarTime = barTime - ServerTimeOffset * 3600;
      int barUtcHour = TimeHour(utcBarTime);

      if(barUtcHour >= rangeStartUTC && barUtcHour < rangeEndUTC)
      {
         barsInRange++;

         double high = iHigh(Symbol(), PERIOD_M1, i);
         double low = iLow(Symbol(), PERIOD_M1, i);

         // Debug: mostrar primeras 3 barras encontradas
         if(barsInRange <= 3)
         {
            Print("Barra #", barsInRange, " - Hora UTC: ", TimeToString(utcBarTime, TIME_MINUTES), 
                  " | High: ", high, " | Low: ", low);
         }

         if(high > rangeHigh) rangeHigh = high;
         if(low < rangeLow) rangeLow = low;
      }
   }

   Print("════════════════════════════════════════");
   Print("RESULTADO:");
   Print("Total barras revisadas: ", barsChecked);
   Print("Barras en período de rango: ", barsInRange);
   Print("Range High: ", rangeHigh);
   Print("Range Low: ", rangeLow);

   if(barsInRange == 0)
   {
      Print("⚠️⚠️⚠️ ADVERTENCIA: No se encontraron barras en el período del rango");
      Print("Posibles causas:");
      Print("  - ServerTimeOffset incorrecto (actual: ", ServerTimeOffset, ")");
      Print("  - IsWinterTime incorrecto (actual: ", IsWinterTime, ")");
      Print("  - Datos del broker no disponibles");
   }
   else if(rangeLow >= 999999)
   {
      Print("⚠️⚠️⚠️ ERROR: rangeLow no se actualizó (", rangeLow, ")");
      Print("Esto NO debería pasar si se encontraron ", barsInRange, " barras");
   }

   Print("════════════════════════════════════════");
}

