void FinalizeRange()
{
   Print("════════════════════════════════════════");
   Print("FINALIZANDO RANGO...");
   Print("rangeHigh: ", rangeHigh);
   Print("rangeLow: ", rangeLow);

   if(rangeHigh > 0 && rangeLow < 999999 && (rangeHigh - rangeLow) > 0)
   {
      rangeSet = true;
      Print("╔══════════════════════════════════════════════════╗");
      Print("║         ✅ RANGO ESTABLECIDO ✅                  ║");
      Print("╚══════════════════════════════════════════════════╝");
      Print("Range High: ", rangeHigh);
      Print("Range Low: ", rangeLow);
      Print("Range Size: ", CalculatePips(rangeHigh - rangeLow), " pips");

      DrawRangeLines();

      if(EnableAlerts)
      {
         Alert("✅ RANGO ESTABLECIDO - ", CalculatePips(rangeHigh - rangeLow), " pips");
      }
   }
   else
   {
      Print("╔══════════════════════════════════════════════════╗");
      Print("║   ❌❌❌ ERROR AL FINALIZAR RANGO ❌❌❌         ║");
      Print("╚══════════════════════════════════════════════════╝");

      if(rangeHigh <= 0)
      {
         Print("❌ rangeHigh = ", rangeHigh, " (debe ser > 0)");
      }

      if(rangeLow >= 999999)
      {
         Print("❌ rangeLow = ", rangeLow, " (nunca se actualizó desde el valor inicial)");
         Print("Esto indica que NO se encontraron barras en el período del rango");
      }

      if(rangeHigh > 0 && rangeLow < 999999 && (rangeHigh - rangeLow) <= 0)
      {
         Print("❌ Diferencia inválida: ", (rangeHigh - rangeLow));
      }

      Print("");
      Print("DIAGNÓSTICO:");
      Print("ServerTimeOffset: ", ServerTimeOffset);
      Print("IsWinterTime: ", IsWinterTime);
      Print("Período UTC buscado: ", rangeStartUTC, ":00 - ", rangeEndUTC, ":00");
      Print("Hora actual UTC: ", TimeToString(GetUTCTime(), TIME_MINUTES));
      Print("");
      Print("SOLUCIÓN:");
      Print("1. Verifica que ServerTimeOffset sea correcto");
      Print("2. Verifica que IsWinterTime sea correcto");
      Print("3. Revisa los logs de UpdateRange() arriba");

      Alert("❌ ERROR: No se pudo establecer el rango. Revisa los logs en Experts.");
   }

   Print("════════════════════════════════════════");
}

